using System;
using WMS.StockReservation.Core.Domain;
using WMS.StockReservation.Core.Interfaces;

namespace WMS.StockReservation.Strategies
{
    /// <summary>
    /// Handler base para la cadena de responsabilidad.
    /// Implementa el patrГіn Chain of Responsibility con paso al siguiente handler.
    /// Target: ~70 lГӯneas
    /// </summary>
    public abstract class BaseReservationHandler : IReservationHandler
    {
        protected IReservationHandler _nextHandler;
        protected IReservationLogger _logger;

        protected BaseReservationHandler(IReservationLogger logger)
        {
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
        }

        public IReservationHandler SetNext(IReservationHandler next)
        {
            _nextHandler = next;
            return next;
        }

        public HandlerResult Handle(ReservationContext context)
        {
            if (context == null)
                throw new ArgumentNullException(nameof(context));

            // Intentar procesar localmente
            var result = ProcessInternal(context);

            // Si completamos la reserva, retornar directamente
            if (context.IsQuantityFullyReserved())
            {
                _logger.LogCheckpoint($"#{GetType().Name}_COMPLETED");
                return result;
            }

            // Si aГәn hay cantidad pendiente, pasar al siguiente handler
            if (_nextHandler != null && context.PendingQuantity > 0.000001)
            {
                _logger.LogCheckpoint($"#{GetType().Name}_PASS_TO_NEXT");

                var nextResult = _nextHandler.Handle(context);

                // Combinar resultados
                result.ReservedQuantity += nextResult.ReservedQuantity;
                result.Reservations.AddRange(nextResult.Reservations);
                result.CaseCode += (string.IsNullOrEmpty(result.CaseCode) ? "" : "+") + nextResult.CaseCode;
                result.Message += (string.IsNullOrEmpty(result.Message) ? "" : " | ") + nextResult.Message;
            }

            return result;
        }

        /// <summary>
        /// Procesamiento especГӯfico del handler. Debe ser implementado por clases hijas.
        /// </summary>
        protected abstract HandlerResult ProcessInternal(ReservationContext context);

        /// <summary>
        /// Verifica si el handler puede procesar en el contexto actual.
        /// Retorna true si hay stock disponible para este handler.
        /// </summary>
        protected abstract bool CanProcess(ReservationContext context);
    }
}

ARCHITECTURE_CONTROL_FLOW.md.content:
# Control Flow & Logging Specification - Stock Reservation V2

## PropГіsito
Este documento complementa ARCHITECTURE_V2.md con especificaciones detalladas de:
1. El algoritmo exacto del loop de reserva con re-entry
2. El mapeo completo de checkpoints de logging (CASO_#XX)
3. Ownership y mutaciГіn de colecciones compartidas

---

## 1. ALGORITMO DE RESERVA: Loop Iterativo con Re-Entry

### PseudocГіdigo Detallado

```csharp
public class ReservationLoopStep : IPipelineStep
{
    public void Execute(ReservationContext context)
    {
        const int MAX_ITERATIONS = 10;
        int iteration = 0;
        bool hasProgress = true;

        while (context.PendingQuantity > 0.000001 && 
               iteration < MAX_ITERATIONS && 
               hasProgress)
        {
            iteration++;
            double previousPending = context.PendingQuantity;

            // ===== FASE 1: DETERMINAR PUNTO DE INICIO =====
            DetermineStartingPoint(context);

            // ===== FASE 2: CONSTRUIR/RESETEAR CADENA =====
            var handlerChain = BuildHandlerChainForIteration(context);

            // ===== FASE 3: EJECUTAR CADENA =====
            var result = handlerChain.Handle(context);

            // ===== FASE 4: PROCESAR RESULTADO =====
            if (result.Success && result.ReservedQuantity > 0)
            {
                context.PendingQuantity -= result.ReservedQuantity;
                context.PendingQuantity = Math.Round(context.PendingQuantity, 6);
                context.CreatedReservations.AddRange(result.Reservations);
            }

            // ===== FASE 5: EVALUAR PROGRESO =====
            hasProgress = Math.Abs(previousPending - context.PendingQuantity) > 0.000001;

            if (!hasProgress)
            {
                // No hubo reserva, intentar fallback
                if (TryEnableExplosionFallback(context))
                {
                    _logger.LogCheckpoint("#MI3_FALLBACK_EXPLOSION_ENABLED");

                    // RE-QUERY stock con explosiГіn habilitada
                    ReQueryStockForExplosion(context);

                    hasProgress = true; // Permitir otra iteraciГіn
                    continue;
                }
                else if (TryEnableUMBasFallback(context))
                {
                    _logger.LogCheckpoint("#MI3_FALLBACK_UMBAS_ENABLED");

                    // RE-QUERY stock en UMBas
                    ReQueryStockForUMBas(context);

                    hasProgress = true; // Permitir otra iteraciГіn
                    continue;
                }
                else
                {
                    // No hay mГЎs fallbacks disponibles
                    _logger.LogWarning("#MI3_NO_MORE_FALLBACKS");
                    break;
                }
            }

            // ===== FASE 6: RE-CALCULAR FECHAS =====
            if (context.PendingQuantity > 0.000001)
            {
                RecalculateExpirationDates(context);
            }
        }

        if (iteration >= MAX_ITERATIONS)
        {
            _logger.LogError($"#MI3_MAX_ITERATIONS_REACHED - {MAX_ITERATIONS}");
        }

        ValidateIncompletOrderRejection(context);
    }

    /// <summary>
    /// Construir cadena de handlers segГәn el StartingPoint actual.
    /// Esto permite RE-ENTRY: despuГ©s de un fallback, la cadena se reconstruye.
    /// </summary>
    private IReservationHandler BuildHandlerChainForIteration(ReservationContext context)
    {
        // Todos los handlers disponibles (en orden de prioridad)
        var completeHandler = new CompletePackagesHandler(...);
        var incompleteHandler = new IncompletePackagesHandler(...);
        var pickingHandler = new PickingZoneHandler(...);
        var nonPickingHandler = new NonPickingZoneHandler(...);
        var umBasHandler = new UMBasExplosionHandler(...);

        // Dependiendo de StartingPoint, conectar la cadena desde un punto diferente
        switch (context.StartingPoint)
        {
            case 1: // INICIAR_EN_1: Empezar desde pallets completos
                completeHandler.SetNext(incompleteHandler);
                incompleteHandler.SetNext(pickingHandler);
                pickingHandler.SetNext(nonPickingHandler);
                nonPickingHandler.SetNext(umBasHandler);
                return completeHandler; // Retorna el primero

            case 2: // INICIAR_EN_2: Empezar desde pallets incompletos
                incompleteHandler.SetNext(pickingHandler);
                pickingHandler.SetNext(nonPickingHandler);
                nonPickingHandler.SetNext(umBasHandler);
                return incompleteHandler;

            case 3: // INICIAR_EN_3: Empezar desde picking zone
                pickingHandler.SetNext(nonPickingHandler);
                nonPickingHandler.SetNext(umBasHandler);
                return pickingHandler;

            case 4: // INICIAR_EN_4: Empezar desde almacГ©n general
                nonPickingHandler.SetNext(umBasHandler);
                return nonPickingHandler;

            default: // Caso 0: Empezar desde Гәltima lista (general)
                nonPickingHandler.SetNext(umBasHandler);
                return nonPickingHandler;
        }
    }

    private bool TryEnableExplosionFallback(ReservationContext context)
    {
        if (context.IsExplosionModeEnabled) return false; // Ya intentado
        if (!context.Configuration.Explosion_Automatica) return false;
        if (context.Request.IdPresentacion == 0) return false; // Ya en UMBas
        if (context.DefaultPresentation == null) return false;

        context.IsExplosionModeEnabled = true;
        return true;
    }

    private bool TryEnableUMBasFallback(ReservationContext context)
    {
        if (context.IsUMBasModeEnabled) return false; // Ya intentado
        if (context.Request.IdPresentacion != 0) return false; // No aplica
        if (context.DefaultPresentation == null) return false;

        // Buscar si hay stock en UMBas cuando se pidiГі en presentaciГіn
        context.IsUMBasModeEnabled = true;
        return true;
    }

    private void ReQueryStockForExplosion(ReservationContext context)
    {
        // Crear nueva bГәsqueda con IdPresentacion = 0 (UMBas)
        var explosionRequest = context.Request.Clone();
        explosionRequest.IdPresentacion = 0;

        // Re-consultar stock
        var newStock = clsLnStock.lStock(
            explosionRequest,
            context.Product,
            context.Configuration.Dias_diferencia_fecha_vencimiento,
            context.Configuration,
            context.Connection,
            context.Transaction,
            soloPickingZone: false,
            soloNonPickingZone: false,
            context.TareaReabasto,
            context.EsDevolucion);

        if (newStock != null && newStock.Count > 0)
        {
            clsLnStock_res.Restar_Stock_Reservado(newStock, context.Configuration, 
                                                   context.Connection, context.Transaction);
            newStock = newStock.Where(s => s.Cantidad > 0).ToList();

            // REEMPLAZAR WorkingStockList con el nuevo stock
            context.WorkingStockList = newStock;
        }
    }

    private void ReQueryStockForUMBas(ReservationContext context)
    {
        // Similar a ReQueryStockForExplosion pero buscar solo en UMBas
        // ...
    }

    private void RecalculateExpirationDates(ReservationContext context)
    {
        // DespuГ©s de reservar, las listas de stock cambiaron
        // Re-calcular fechas mГӯnimas para la siguiente iteraciГіn

        if (context.WorkingStockList != null && context.WorkingStockList.Count > 0)
        {
            var validStock = context.WorkingStockList.Where(s => s.Cantidad > 0).ToList();
            if (validStock.Count > 0)
            {
                context.GlobalMinimumExpirationDate = validStock.Min(s => s.Fecha_vence);
            }
        }
    }
}
