/// (durante re-query por fallback).
/// </summary>
private void ReQueryStockForExplosion(ReservationContext context)
{
    var newStock = clsLnStock.lStock(...);

    // вң… CORRECTO: ReservationLoopStep reemplaza lista
    context.WorkingStockList = newStock; // вң… PERMITIDO en este step
}

/// <summary>
/// REGLA 3: Handlers DEBEN llamar Restar_Stock_Reservado despuГ©s de insertar.
/// </summary>
public class NonPickingZoneHandler : BaseReservationHandler
{
    protected override HandlerResult ProcessReservation(ReservationContext context)
    {
        foreach (var stock in context.WorkingStockList)
        {
            // Reservar...
            clsLnStock_res.Insertar(reservation, ...);

            // вң… OBLIGATORIO: Restar stock reservado de TODAS las listas afectadas
            clsLnStock_res.Restar_Stock_Reservado(
                context.WorkingStockList,
                context.Configuration,
                context.Connection,
                context.Transaction);

            // Si afecta a picking zone, tambiГ©n restar de esa lista
            if (stock.UbicacionPicking && context.StockListPickingZone != null)
            {
                clsLnStock_res.Restar_Stock_Reservado(
                    context.StockListPickingZone,
                    context.Configuration,
                    context.Connection,
                    context.Transaction);
            }
        }

        return result;
    }
}

/// <summary>
/// REGLA 4: CachГ©s (CachedLocations, CachedPresentations) son append-only.
/// </summary>
public class CompletePackagesHandler : BaseReservationHandler
{
    protected override HandlerResult ProcessReservation(ReservationContext context)
    {
        var ubicacion = GetUbicacionFromCacheOrQuery(stock.IdUbicacion, context);
        // ...
    }

    private clsBeBodega_ubicacion GetUbicacionFromCacheOrQuery(int idUbicacion, ReservationContext context)
    {
        // вң… CORRECTO: Buscar en cachГ© primero
        var cached = context.CachedLocations.FirstOrDefault(u => u.IdUbicacion == idUbicacion);
        if (cached != null) return cached.Clone();

        // Si no estГЎ, consultar BD y agregar a cachГ©
        var ubicacion = clsLnBodega_ubicacion.Get_Single_By_IdUbicacion_And_IdBodega(...);

        // вң… PERMITIDO: Append al cachГ©
        context.CachedLocations.Add(ubicacion.Clone());

        return ubicacion;
    }
}
```

### Diagrama de MutaciГіn

