using System;
using System.Data;
using System.Linq;

namespace WMS.StockReservation.Testing.Database
{
    /// <summary>
    /// Analizador de datos de producciГіn para entender:
    /// - Estructura de bodega (ГҒrea вҶ’ Sector вҶ’ Tramo вҶ’ UbicaciГіn)
    /// - Estrategias de rotaciГіn (FIFO, LIFO, FEFO)
    /// - Rutas Гіptimas de picking
    /// </summary>
    public class ProductionDataAnalyzer
    {
        private readonly ProductionDatabaseConnection _connection;

        public ProductionDataAnalyzer(ProductionDatabaseConnection connection)
        {
            _connection = connection ?? throw new ArgumentNullException(nameof(connection));
        }

        public void AnalyzeWarehouseStructure()
        {
            Console.WriteLine("\nрҹ“Ҡ ANГҒLISIS DE ESTRUCTURA DE BODEGA\n");
            Console.WriteLine(new string('в•җ', 70));

            // Bodegas
            var bodegas = _connection.ExecuteQuery(@"
                SELECT COUNT(*) as Total, 
                       SUM(CASE WHEN activo=1 THEN 1 ELSE 0 END) as Activas
                FROM bodega");
            Console.WriteLine($"\nрҹҸў Bodegas: {bodegas.Rows[0]["Total"]} total, {bodegas.Rows[0]["Activas"]} activas");

            // ГҒreas
            var areas = _connection.ExecuteQuery(@"
                SELECT IdBodega, COUNT(*) as TotalAreas
                FROM bodega_area
                WHERE activo = 1
                GROUP BY IdBodega");
            Console.WriteLine($"\nрҹ“Ұ ГҒreas por bodega:");
            foreach (DataRow row in areas.Rows)
            {
                Console.WriteLine($"   Bodega {row["IdBodega"]}: {row["TotalAreas"]} ГЎreas");
            }

            // Sectores
            var sectores = _connection.ExecuteQuery(@"
                SELECT IdBodega, COUNT(*) as TotalSectores
                FROM bodega_sector
                WHERE activo = 1
                GROUP BY IdBodega");
            Console.WriteLine($"\nрҹ”І Sectores por bodega:");
            foreach (DataRow row in sectores.Rows)
            {
                Console.WriteLine($"   Bodega {row["IdBodega"]}: {row["TotalSectores"]} sectores");
            }

            // Tramos
            var tramos = _connection.ExecuteQuery(@"
                SELECT IdBodega, 
                       COUNT(*) as Total,
                       SUM(CASE WHEN orden_descendente=1 THEN 1 ELSE 0 END) as Descendentes
                FROM bodega_tramo
                WHERE activo = 1
                GROUP BY IdBodega");
            Console.WriteLine($"\nрҹ“Ҹ Tramos por bodega:");
            foreach (DataRow row in tramos.Rows)
            {
                Console.WriteLine($"   Bodega {row["IdBodega"]}: {row["Total"]} tramos " +
                                $"({row["Descendentes"]} con orden descendente)");
            }

            // Ubicaciones
            var ubicaciones = _connection.ExecuteQuery(@"
                SELECT IdBodega,
                       COUNT(*) as Total,
                       SUM(CASE WHEN ubicacion_picking=1 THEN 1 ELSE 0 END) as Picking,
                       SUM(CASE WHEN ubicacion_picking=0 THEN 1 ELSE 0 END) as NoPicking,
                       MAX(nivel) as MaxNivel
                FROM bodega_ubicacion
                WHERE activo = 1
                GROUP BY IdBodega");
            Console.WriteLine($"\nрҹ“Қ Ubicaciones por bodega:");
            foreach (DataRow row in ubicaciones.Rows)
            {
                Console.WriteLine($"   Bodega {row["IdBodega"]}: {row["Total"]} ubicaciones " +
                                $"({row["Picking"]} Picking, {row["NoPicking"]} No-Picking, {row["MaxNivel"]} niveles)");
            }
        }

        public void AnalyzeRotationStrategies()
        {
            Console.WriteLine("\nрҹ”„ ANГҒLISIS DE ESTRATEGIAS DE ROTACIГ“N\n");
            Console.WriteLine(new string('в•җ', 70));

            var rotacion = _connection.ExecuteQuery(@"
                SELECT tr.IdTipoRotacion, tr.Codigo, tr.Descripcion, 
                       COUNT(DISTINCT u.IdUbicacion) as Ubicaciones
                FROM tipo_rotacion tr
                LEFT JOIN bodega_ubicacion u ON tr.IdTipoRotacion = u.IdTipoRotacion
                WHERE tr.activo = 1
                GROUP BY tr.IdTipoRotacion, tr.Codigo, tr.Descripcion
                ORDER BY Ubicaciones DESC");

            Console.WriteLine($"\nTipos de RotaciГіn configurados:");
            foreach (DataRow row in rotacion.Rows)
            {
                var codigo = row["Codigo"]?.ToString() ?? "N/A";
                var descripcion = row["Descripcion"]?.ToString() ?? "Sin descripciГіn";
                var ubicaciones = row["Ubicaciones"];
                Console.WriteLine($"   {codigo,-10} {descripcion,-30} ({ubicaciones,5} ubicaciones)");
            }
        }

        public void AnalyzeStockDistribution()
        {
            Console.WriteLine("\nрҹ“Ұ ANГҒLISIS DE DISTRIBUCIГ“N DE STOCK\n");
            Console.WriteLine(new string('в•җ', 70));

            var stockPorBodega = _connection.ExecuteQuery(@"
                SELECT s.IdBodega,
                       COUNT(DISTINCT s.IdStock) as TotalRegistros,
                       SUM(s.cantidad) as CantidadTotal,
                       COUNT(DISTINCT s.IdProductoBodega) as ProductosUnicos,
                       COUNT(DISTINCT s.IdUbicacion) as UbicacionesUsadas,
                       SUM(CASE WHEN s.Uds_lic_plate IS NOT NULL THEN 1 ELSE 0 END) as PalletsCompletos
                FROM stock s
                WHERE s.activo = 1
                GROUP BY s.IdBodega");

            Console.WriteLine($"\nStock por bodega:");
            foreach (DataRow row in stockPorBodega.Rows)
            {
                Console.WriteLine($"\n   Bodega {row["IdBodega"]}:");
                Console.WriteLine($"      Registros stock: {Convert.ToInt32(row["TotalRegistros"]):N0}");
                Console.WriteLine($"      Cantidad total: {Convert.ToDouble(row["CantidadTotal"]):N2}");
                Console.WriteLine($"      Productos Гәnicos: {row["ProductosUnicos"]}");
                Console.WriteLine($"      Ubicaciones usadas: {row["UbicacionesUsadas"]}");
                Console.WriteLine($"      Pallets completos: {row["PalletsCompletos"]}");
            }

            // Stock en zonas Picking vs No-Picking
            var stockZonas = _connection.ExecuteQuery(@"
                SELECT u.ubicacion_picking,
                       COUNT(DISTINCT s.IdStock) as Registros,
                       SUM(s.cantidad) as Cantidad
                FROM stock s
                INNER JOIN bodega_ubicacion u ON s.IdUbicacion = u.IdUbicacion AND s.IdBodega = u.IdBodega
                WHERE s.activo = 1
                GROUP BY u.ubicacion_picking");

            Console.WriteLine($"\nрҹ“Қ DistribuciГіn por zona:");
            foreach (DataRow row in stockZonas.Rows)
            {
                var zona = Convert.ToBoolean(row["ubicacion_picking"]) ? "Picking" : "No-Picking";
                Console.WriteLine($"   {zona,-15}: {Convert.ToInt32(row["Registros"]):N0} registros, " +
                                $"{Convert.ToDouble(row["Cantidad"]):N2} unidades");
            }
        }

        public void AnalyzePickingRoutes()
        {
            Console.WriteLine("\nрҹӣӨпёҸ  ANГҒLISIS DE RUTAS DE PICKING\n");
            Console.WriteLine(new string('в•җ', 70));

            // Ubicaciones por nivel y orientaciГіn
            var rutasPorNivel = _connection.ExecuteQuery(@"
                SELECT nivel, orientacion_pos, COUNT(*) as Ubicaciones
                FROM bodega_ubicacion
                WHERE activo = 1 AND ubicacion_picking = 1
                GROUP BY nivel, orientacion_pos
                ORDER BY nivel, orientacion_pos");

            Console.WriteLine($"\nUbicaciones Picking por nivel y orientaciГіn:");
            var nivelActual = -1;
            foreach (DataRow row in rutasPorNivel.Rows)
            {
                var nivel = Convert.ToInt32(row["nivel"]);
                if (nivel != nivelActual)
                {
                    Console.WriteLine($"\n   Nivel {nivel}:");
                    nivelActual = nivel;
                }
                var orientacion = row["orientacion_pos"]?.ToString() ?? "N/A";
                Console.WriteLine($"      OrientaciГіn {orientacion}: {row["Ubicaciones"]} ubicaciones");
            }

            // Tramos con orden descendente (optimizaciГіn de ruta)
            var tramosDescendentes = _connection.ExecuteQuery(@"
                SELECT IdBodega, COUNT(*) as Total
                FROM bodega_tramo
                WHERE activo = 1 AND orden_descendente = 1
                GROUP BY IdBodega");

            Console.WriteLine($"\nв¬ҮпёҸ  Tramos con orden descendente (optimizaciГіn):");
            foreach (DataRow row in tramosDescendentes.Rows)
            {
                Console.WriteLine($"   Bodega {row["IdBodega"]}: {row["Total"]} tramos");
            }
        }

        public void GenerateWarehouseReport()
        {
            Console.WriteLine("\nв•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—");
            Console.WriteLine("в•‘          REPORTE COMPLETO DE BODEGA - PRODUCCIГ“N                   в•‘");
            Console.WriteLine("в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ");

            try
            {
                AnalyzeWarehouseStructure();
                AnalyzeRotationStrategies();
                AnalyzeStockDistribution();
                AnalyzePickingRoutes();

                Console.WriteLine("\n" + new string('в•җ', 70));
                Console.WriteLine("вң… AnГЎlisis completado exitosamente");
                Console.WriteLine(new string('в•җ', 70) + "\n");
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"\nвқҢ Error durante el anГЎlisis: {ex.Message}");
                Console.ResetColor();
            }
        }
    }
}

