using System;
using System.Data;
using WMS.StockReservation.Core.Domain;

namespace WMS.StockReservation.Testing.Database
{
    /// <summary>
    /// Seeder para poblar la base de datos de testing con datos realistas.
    /// </summary>
    public class TestDataSeeder
    {
        private readonly IDbConnection _connection;
        private int _nextStockId = 1;
        private int _nextStockResId = 1;

        public TestDataSeeder(IDbConnection connection)
        {
            _connection = connection ?? throw new ArgumentNullException(nameof(connection));
        }

        public void SeedBasicMasterData()
        {
            // Unidad de medida base
            Execute($@"INSERT INTO unidad_medida (IdUnidadMedida, Codigo, Nombre, Activo) 
                      VALUES (1, 'UND', 'Unidades', 1)");

