                      VALUES (1, 'PROP001', 'Propietario Principal', 1)");

            // Estado de producto
            Execute($@"INSERT INTO producto_estado (IdEstado, Codigo, Nombre, Activo) 
                      VALUES (1, 'OK', 'Bueno', 1)");

            // Bodega
            Execute($@"INSERT INTO bodega (IdBodega, Codigo, Nombre, Permitir_Decimales, Activo) 
                      VALUES (1, 'BOD001', 'Bodega Principal', 1, 1)");

            // Ubicaciones: Picking
            Execute($@"INSERT INTO bodega_ubicacion (IdUbicacion, IdBodega, Codigo, Nombre, EsPicking, Nivel, Activo) 
                      VALUES (1, 1, 'PICK-001', 'Picking Zona A', 1, 0, 1)");

            Execute($@"INSERT INTO bodega_ubicacion (IdUbicacion, IdBodega, Codigo, Nombre, EsPicking, Nivel, Activo) 
                      VALUES (2, 1, 'PICK-002', 'Picking Zona B', 1, 0, 1)");

            // Ubicaciones: Non-Picking (Racks nivel 1, 2, 3)
            Execute($@"INSERT INTO bodega_ubicacion (IdUbicacion, IdBodega, Codigo, Nombre, EsPicking, Nivel, Activo) 
                      VALUES (3, 1, 'RACK-A01', 'Rack A Nivel 1', 0, 1, 1)");

            Execute($@"INSERT INTO bodega_ubicacion (IdUbicacion, IdBodega, Codigo, Nombre, EsPicking, Nivel, Activo) 
                      VALUES (4, 1, 'RACK-A02', 'Rack A Nivel 2', 0, 2, 1)");

            Execute($@"INSERT INTO bodega_ubicacion (IdUbicacion, IdBodega, Codigo, Nombre, EsPicking, Nivel, Activo) 
                      VALUES (5, 1, 'RACK-B01', 'Rack B Nivel 1', 0, 1, 1)");

            // Producto
