                      VALUES (1, 1, 100, 1, 100, 0, 1, 1)");
        }

        public void SeedScenario_CompletePackages_Clavaud()
        {
            // Escenario: Pallets completos en zona non-picking (Clavaud)
            // 3 pallets completos con diferentes fechas de vencimiento

            DateTime baseDate = DateTime.Now.AddDays(30);

            // Pallet 1: Fecha mГЎs cercana (debe reservarse primero)
            AddStock(new clsBeStock
            {
                IdBodega = 1,
                IdProductoBodega = 100,
                IdPropietarioBodega = 1,
