                Cantidad = 10, // 10 cajas
                Fecha_vence = baseDate,
                Uds_lic_plate = 10 // Pallet completo
            });

            // Pallet 2: Fecha intermedia
            AddStock(new clsBeStock
            {
                IdBodega = 1,
                IdProductoBodega = 100,
                IdPropietarioBodega = 1,
                IdProductoEstado = 1,
                IdPresentacion = 1,
                IdUnidadMedida = 1,
                IdUbicacion = 4, // Rack nivel 2
                Lote = "LOTE002",
