                Fecha_vence = baseDate.AddDays(10),
                Uds_lic_plate = 15 // Pallet completo
            });

            // Pallet 3: Fecha mГЎs lejana
            AddStock(new clsBeStock
            {
                IdBodega = 1,
                IdProductoBodega = 100,
                IdPropietarioBodega = 1,
                IdProductoEstado = 1,
                IdPresentacion = 1,
                IdUnidadMedida = 1,
