                Uds_lic_plate = 20 // Pallet completo
            });
        }

        public void SeedScenario_IncompletePackages()
        {
            // Escenario: Pallets incompletos (stock < uds_lic_plate)
            DateTime baseDate = DateTime.Now.AddDays(25);

            AddStock(new clsBeStock
            {
                IdBodega = 1,
                IdProductoBodega = 100,
                IdPropietarioBodega = 1,
                IdProductoEstado = 1,
                IdPresentacion = 1,
