        }

        public void SeedScenario_PickingZone()
        {
            // Escenario: Stock en zona picking
            DateTime baseDate = DateTime.Now.AddDays(15);

            AddStock(new clsBeStock
            {
                IdBodega = 1,
                IdProductoBodega = 100,
                IdPropietarioBodega = 1,
                IdProductoEstado = 1,
                IdPresentacion = 1,
                IdUnidadMedida = 1,
                IdUbicacion = 1, // Picking
                Lote = "LOTE005",
                Lic_plate = "PICK001",
                Cantidad = 5,
                Fecha_vence = baseDate,
                Uds_lic_plate = null // No es pallet
            });
        }

        public void SeedScenario_DecimalQuantities()
        {
            // Escenario: Cantidades decimales (0.5 cajas = 6 unidades)
            DateTime baseDate = DateTime.Now.AddDays(20);

            AddStock(new clsBeStock
            {
                IdBodega = 1,
                IdProductoBodega = 100,
                IdPropietarioBodega = 1,
                IdProductoEstado = 1,
                IdPresentacion = 1,
