                Lic_plate = "DECIMAL001",
                Cantidad = 2.5, // 2.5 cajas
                Fecha_vence = baseDate,
                Uds_lic_plate = null
            });
        }

        public void SeedScenario_MixedStock()
        {
            // Escenario completo: Pallets completos + incompletos + picking + decimales
            DateTime baseDate = DateTime.Now.AddDays(30);

            // Pallet completo fecha cercana (non-picking)
            AddStock(new clsBeStock
            {
                IdBodega = 1,
                IdProductoBodega = 100,
                IdPropietarioBodega = 1,
                IdProductoEstado = 1,
                IdPresentacion = 1,
                IdUnidadMedida = 1,
                IdUbicacion = 3,
                Lote = "LOTE010",
                Lic_plate = "PALLET010",
                Cantidad = 10,
                Fecha_vence = baseDate.AddDays(5),
                Uds_lic_plate = 10
            });

            // Pallet incompleto (non-picking)
            AddStock(new clsBeStock
            {
                IdBodega = 1,
                IdProductoBodega = 100,
                IdPropietarioBodega = 1,
                IdProductoEstado = 1,
                IdPresentacion = 1,
                IdUnidadMedida = 1,
                IdUbicacion = 4,
                Lote = "LOTE011",
                Lic_plate = "PALLET011",
                Cantidad = 6,
                Fecha_vence = baseDate.AddDays(3),
                Uds_lic_plate = 10
            });

            // Stock picking (fecha mГЎs cercana - debe usarse primero)
            AddStock(new clsBeStock
            {
                IdBodega = 1,
                IdProductoBodega = 100,
                IdPropietarioBodega = 1,
                IdProductoEstado = 1,
                IdPresentacion = 1,
                IdUnidadMedida = 1,
                IdUbicacion = 1,
                Lote = "LOTE012",
                Lic_plate = "PICK010",
                Cantidad = 15,
                Fecha_vence = baseDate, // Fecha mГЎs cercana
                Uds_lic_plate = null
            });
        }

        private void AddStock(clsBeStock stock)
        {
            stock.IdStock = _nextStockId++;
            stock.User_agr = "TEST";
            stock.Fec_agr = DateTime.Now;
            stock.User_mod = "TEST";
            stock.Fec_mod = DateTime.Now;
            stock.Activo = true;

            if (stock.Fecha_ingreso == DateTime.MinValue)
                stock.Fecha_ingreso = DateTime.Now.AddDays(-30);

            string sql = $@"
                INSERT INTO stock (
                    IdStock, IdBodega, IdPropietarioBodega, IdProductoBodega, IdProductoEstado,
                    IdPresentacion, IdUnidadMedida, IdUbicacion, lote, lic_plate,
                    cantidad, fecha_ingreso, fecha_vence, uds_lic_plate,
                    user_agr, fec_agr, user_mod, fec_mod, activo
                ) VALUES (
                    {stock.IdStock}, {stock.IdBodega}, {stock.IdPropietarioBodega}, 
                    {stock.IdProductoBodega}, {stock.IdProductoEstado},
                    {(stock.IdPresentacion.HasValue ? stock.IdPresentacion.Value.ToString() : "NULL")}, 
                    {(stock.IdUnidadMedida.HasValue ? stock.IdUnidadMedida.Value.ToString() : "NULL")}, 
                    {stock.IdUbicacion}, '{stock.Lote}', '{stock.Lic_plate}',
                    {stock.Cantidad}, '{stock.Fecha_ingreso:yyyy-MM-dd HH:mm:ss}', 
                    '{stock.Fecha_vence:yyyy-MM-dd HH:mm:ss}', 
                    {(stock.Uds_lic_plate.HasValue ? stock.Uds_lic_plate.Value.ToString() : "NULL")},
                    '{stock.User_agr}', '{stock.Fec_agr:yyyy-MM-dd HH:mm:ss}', 
                    '{stock.User_mod}', '{stock.Fec_mod:yyyy-MM-dd HH:mm:ss}', {(stock.Activo ? 1 : 0)}
                )";

            Execute(sql);
        }

        private void Execute(string sql)
        {
            using (var cmd = _connection.CreateCommand())
            {
                cmd.CommandText = sql;
                cmd.ExecuteNonQuery();
            }
        }
    }
}

Infrastructure/Logging/ReservationLogger.content:
using System;
using System.Collections.Generic;
using WMS.StockReservation.Core.Interfaces;

namespace WMS.StockReservation.Infrastructure.Logging
{
    /// <summary>
    /// ImplementaciГіn del logger de reservas.
    /// Mantiene compatibilidad con el sistema de logging original (CASO_#XX).
    /// </summary>
    public class ReservationLogger : IReservationLogger
    {
        private readonly List<string> _messages = new List<string>();

        public void LogCheckpoint(string checkpoint)
        {
            var message = $"[CHECKPOINT] {DateTime.Now:yyyy-MM-dd HH:mm:ss.fff} - {checkpoint}";
            _messages.Add(message);
            Console.WriteLine(message);
        }

        public void LogInfo(string message)
        {
            var logMessage = $"[INFO] {DateTime.Now:yyyy-MM-dd HH:mm:ss.fff} - {message}";
            _messages.Add(logMessage);
            Console.WriteLine(logMessage);
        }

        public void LogWarning(string message)
        {
            var logMessage = $"[WARNING] {DateTime.Now:yyyy-MM-dd HH:mm:ss.fff} - {message}";
            _messages.Add(logMessage);
            Console.WriteLine(logMessage);
        }

        public void LogError(string message)
        {
            var logMessage = $"[ERROR] {DateTime.Now:yyyy-MM-dd HH:mm:ss.fff} - {message}";
            _messages.Add(logMessage);
            Console.Error.WriteLine(logMessage);
        }

        public void LogReservation(clsBeStock_res reservation, string caseCode, string message)
        {
            var logMessage = $"[RESERVATION] {DateTime.Now:yyyy-MM-dd HH:mm:ss.fff} - {caseCode} - " +
                           $"IdStockRes: {reservation.IdStockRes} - {message}";
            _messages.Add(logMessage);
            Console.WriteLine(logMessage);
        }

        public List<string> GetMessages()
        {
            return new List<string>(_messages);
        }
    }
}

Core/Interfaces/IReservationLogger.cs.content:
namespace WMS.StockReservation.Core.Interfaces
{
    /// <summary>
    /// Interfaz para logging de operaciones de reserva.
    /// Mantiene compatibilidad con el sistema de logging original (CASO_#XX, checkpoints).
    /// </summary>
    public interface IReservationLogger
    {
        /// <summary>
        /// Registra un checkpoint del proceso (e.g., #MI3_VALIDATION_OK).
        /// </summary>
        void LogCheckpoint(string checkpoint);

        /// <summary>
        /// Registra informaciГіn general.
        /// </summary>
        void LogInfo(string message);

        /// <summary>
        /// Registra una advertencia.
        /// </summary>
        void LogWarning(string message);

        /// <summary>
        /// Registra un error.
        /// </summary>
        void LogError(string message);

        /// <summary>
        /// Registra una reserva especГӯfica con su caso y mensaje detallado.
        /// Mapea a Agregar_Log_Reserva del original.
        /// </summary>
        void LogReservation(clsBeStock_res reservation, string caseCode, string message);

        /// <summary>
        /// Obtiene todos los mensajes registrados.
        /// </summary>
        List<string> GetMessages();
    }
}

