        static void RunSyntheticScenarios(TestDatabaseConnection dbConn)
        {
            Console.WriteLine("\nрҹ§Ә EJECUTANDO ESCENARIOS SINTГүTICOS\n");

            // Limpiar datos previos
            dbConn.ClearAllTables();

            // Seed master data
            var seeder = new TestDataSeeder(dbConn.GetConnection());
            seeder.SeedBasicMasterData();

            Console.WriteLine("вң… Datos maestros creados\n");

            // Escenarios
            var scenarios = new List<(string name, Action seedAction)>
            {
                ("Pallets Completos (Clavaud)", () => seeder.SeedScenario_CompletePackages_Clavaud()),
                ("Pallets Incompletos", () => seeder.SeedScenario_IncompletePackages()),
                ("Zona Picking", () => seeder.SeedScenario_PickingZone()),
                ("Cantidades Decimales", () => seeder.SeedScenario_DecimalQuantities()),
                ("Stock Mixto (Completo)", () => seeder.SeedScenario_MixedStock())
            };

            foreach (var (name, seedAction) in scenarios)
            {
                Console.WriteLine($"\nв–¶пёҸ  Escenario: {name}");
                Console.WriteLine(new string('в”Җ', 60));

                seedAction();

                // Ejecutar reserva
                ExecuteTestReservation(dbConn, 50); // Reservar 50 unidades

                Console.WriteLine();
            }
        }

        static void ExecuteTestReservation(TestDatabaseConnection dbConn, double cantidad)
        {
            var conn = dbConn.GetConnection();

            try
            {
                var transaction = conn.BeginTransaction();

                // Crear request
                var request = new clsBeStock_res
                {
                    IdBodega = 1,
                    IdProducto = 100,
                    IdPresentacion = 1, // Caja
                    Cantidad = cantidad,
                    IdPedidoDet = 1,
                    IdPropietarioBodega = 1,
                    IdProductoBodega = 100
                };

                // Obtener configuraciГіn
                var config = new clsBeConfigEnc
                {
                    IdBodega = 1,
                    Conservar_Zona_Picking_Clavaud = true,
                    Explosion_Automatica = true,
                    Rechazar_pedido_incompleto = tRechazarPedidoIncompleto.No,
                    Dias_diferencia_fecha_vencimiento = 0
                };

                Console.WriteLine($"рҹ“қ Solicitado: {cantidad} cajas");

                // Ejecutar algoritmo (usando sobrecarga IDbConnection para testing)
                var startTime = DateTime.Now;
                var reservations = StockReservationFacade.Reserva_Stock_From_MI3(
                    request,
                    100,
                    config,
                    conn,  // IDbConnection directo (SQLite)
                    transaction,  // IDbTransaction directo
                    null,
                    null,
                    0,
                    false,
                    1,
                    Environment.MachineName);

                var elapsed = DateTime.Now - startTime;

                // Mostrar resultados
                Console.WriteLine($"вң… Reservado: {reservations.Sum(r => r.Cantidad)} cajas en {reservations.Count} reservas");
                Console.WriteLine($"вҸұпёҸ  Tiempo: {elapsed.TotalMilliseconds:F2} ms");

                if (reservations.Any())
                {
                    Console.WriteLine("\nрҹ“Ӣ Detalle de reservas:");
                    foreach (var res in reservations)
                    {
                        Console.WriteLine($"   - Stock #{res.IdStock}: {res.Cantidad:F2} ({res.Lic_plate})");
                    }
                }

                transaction.Commit();
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"вқҢ Error: {ex.Message}");
                Console.ResetColor();
            }
        }

        static void ImportRealData(TestDatabaseConnection dbConn)
        {
            Console.WriteLine("\nрҹ“Ҙ IMPORTAR DATOS REALES\n");

            Console.Write("Ruta archivo stock.csv: ");
            var stockPath = Console.ReadLine();

            Console.Write("Ruta archivo stock_res.csv: ");
            var resPath = Console.ReadLine();

            if (!System.IO.File.Exists(stockPath))
            {
                Console.WriteLine($"вқҢ Archivo no encontrado: {stockPath}");
                return;
            }

            if (!System.IO.File.Exists(resPath))
            {
                Console.WriteLine($"вқҢ Archivo no encontrado: {resPath}");
                return;
            }

            Console.WriteLine("\nвҸі Importando datos...");

            var importer = new RealDataImporter(dbConn.GetConnection());
            var result = importer.ImportFromCSV(stockPath, resPath);

            Console.WriteLine($"\n{result}");
        }

        static void RunSingleReservationTest(TestDatabaseConnection dbConn)
        {
            Console.WriteLine("\nрҹ”¬ PRUEBA DE RESERVA INDIVIDUAL\n");

            Console.Write("Cantidad a reservar: ");
            if (!double.TryParse(Console.ReadLine(), out double cantidad))
            {
                Console.WriteLine("вқҢ Cantidad invГЎlida");
                return;
            }

            ExecuteTestReservation(dbConn, cantidad);
        }

        static void ViewDatabaseStats(TestDatabaseConnection dbConn)
        {
            Console.WriteLine("\nрҹ“Ҡ ESTADГҚSTICAS DE LA BASE DE DATOS\n");

            var stats = new[]
            {
                ("Stock", "SELECT COUNT(*), SUM(cantidad) FROM stock"),
                ("Reservas", "SELECT COUNT(*), SUM(cantidad) FROM stock_res"),
                ("Productos", "SELECT COUNT(*) FROM producto"),
                ("Bodegas", "SELECT COUNT(*) FROM bodega"),
                ("Ubicaciones", "SELECT COUNT(*) FROM bodega_ubicacion")
            };

            foreach (var (name, query) in stats)
            {
                var table = dbConn.ExecuteQuery(query);
                if (table.Rows.Count > 0)
                {
                    var row = table.Rows[0];
                    if (row.ItemArray.Length >= 2)
                    {
                        Console.WriteLine($"{name,-15}: {row[0],8} registros | Total: {Convert.ToDouble(row[1] ?? 0):N2}");
                    }
                    else
                    {
                        Console.WriteLine($"{name,-15}: {row[0],8} registros");
                    }
                }
            }
        }

        static void ValidateDataIntegrity(TestDatabaseConnection dbConn)
        {
            Console.WriteLine("\nвң”пёҸ  VALIDACIГ“N DE INTEGRIDAD DE DATOS\n");

            // Validar stock disponible
            var query = @"
                SELECT s.IdStock, s.cantidad as StockTotal,
                       COALESCE(SUM(sr.cantidad), 0) as StockReservado,
                       (s.cantidad - COALESCE(SUM(sr.cantidad), 0)) as Disponible
                FROM stock s
                LEFT JOIN stock_res sr ON s.IdStock = sr.IdStock
                GROUP BY s.IdStock, s.cantidad
                HAVING Disponible < 0";

            var violations = dbConn.ExecuteQuery(query);

            if (violations.Rows.Count == 0)
            {
                Console.WriteLine("вң… No hay violaciones de stock (disponible = stock - reservado)");
            }
            else
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"вқҢ Se encontraron {violations.Rows.Count} violaciones:");
                foreach (System.Data.DataRow row in violations.Rows)
                {
                    Console.WriteLine($"   Stock #{row[0]}: Total={row[1]}, Reservado={row[2]}, Disponible={row[3]}");
                }
                Console.ResetColor();
            }
        }

        static void TestProductionConnection()
        {
            Console.WriteLine("\nрҹҢҗ PRUEBA DE CONEXIГ“N A PRODUCCIГ“N\n");

            try
            {
                using (var prodConn = new ProductionDatabaseConnection())
                {
                    prodConn.TestConnection();

                    var stats = prodConn.ExecuteQuery(@"
                        SELECT 
                            (SELECT COUNT(*) FROM stock WHERE activo=1) as TotalStock,
                            (SELECT COUNT(*) FROM bodega WHERE activo=1) as TotalBodegas,
                            (SELECT COUNT(*) FROM bodega_ubicacion WHERE activo=1) as TotalUbicaciones,
                            (SELECT COUNT(*) FROM tipo_rotacion WHERE activo=1) as TiposRotacion");

                    if (stats.Rows.Count > 0)
                    {
                        var row = stats.Rows[0];
                        Console.WriteLine($"\nрҹ“Ҡ Datos de producciГіn:");
                        Console.WriteLine($"   Stock activo: {row["TotalStock"]:N0} registros");
                        Console.WriteLine($"   Bodegas: {row["TotalBodegas"]} activas");
                        Console.WriteLine($"   Ubicaciones: {row["TotalUbicaciones"]:N0}");
                        Console.WriteLine($"   Tipos de rotaciГіn: {row["TiposRotacion"]}");
                    }
                }
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"вқҢ Error: {ex.Message}");
                Console.ResetColor();
            }
        }

        static void AnalyzeProductionWarehouse()
        {
            Console.WriteLine("\nрҹ“Ҡ ANГҒLISIS DE BODEGA DE PRODUCCIГ“N\n");

            try
            {
                using (var prodConn = new ProductionDatabaseConnection())
                {
                    var analyzer = new ProductionDataAnalyzer(prodConn);
                    analyzer.GenerateWarehouseReport();
                }
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"вқҢ Error: {ex.Message}");
                Console.ResetColor();
            }
        }

        static void RunProductionReservation()
        {
            Console.WriteLine("\nрҹҡҖ EJECUTAR RESERVA CONTRA PRODUCCIГ“N\n");
            Console.WriteLine("вҡ пёҸ  ADVERTENCIA: Esta operaciГіn se ejecutarГЎ contra la base de datos de producciГіn.");
            Console.Write("\nВҝContinuar? (S/N): ");

            var confirm = Console.ReadLine()?.ToUpper();
            if (confirm != "S")
            {
                Console.WriteLine("вқҢ OperaciГіn cancelada");
                return;
            }

            Console.Write("\nID Bodega: ");
            if (!int.TryParse(Console.ReadLine(), out int bodegaId))
            {
                Console.WriteLine("вқҢ ID invГЎlido");
                return;
            }

            Console.Write("ID Producto: ");
            if (!int.TryParse(Console.ReadLine(), out int productoId))
            {
                Console.WriteLine("вқҢ ID invГЎlido");
                return;
            }

            Console.Write("Cantidad a reservar: ");
            if (!double.TryParse(Console.ReadLine(), out double cantidad))
            {
                Console.WriteLine("вқҢ Cantidad invГЎlida");
                return;
            }

            try
            {
                using (var prodConn = new ProductionDatabaseConnection())
                {
                    var conn = prodConn.GetConnection();
                    var transaction = conn.BeginTransaction();

                    try
                    {
                        // Crear request
                        var request = new clsBeStock_res
                        {
                            IdBodega = bodegaId,
                            IdProducto = productoId,
                            Cantidad = cantidad,
                            IdPropietarioBodega = 1
                        };

                        // ConfiguraciГіn (TODO: cargar desde BD)
                        var config = new clsBeConfigEnc
                        {
                            IdBodega = bodegaId,
                            Conservar_Zona_Picking_Clavaud = true,
                            Explosion_Automatica = true,
                            Rechazar_pedido_incompleto = tRechazarPedidoIncompleto.No,
                            Estrategia_Picking = "FEFO"
                        };

                        Console.WriteLine($"\nрҹ“қ Ejecutando reserva...");
                        var startTime = DateTime.Now;

                        var reservations = StockReservationFacade.Reserva_Stock_From_MI3(
                            request,
                            productoId,
                            config,
                            conn,
                            transaction,
                            null,
                            null,
                            0,
                            false,
                            1,
                            Environment.MachineName);

                        var elapsed = DateTime.Now - startTime;

                        Console.WriteLine($"вң… Reservado: {reservations.Sum(r => r.Cantidad)} unidades en {reservations.Count} reservas");
                        Console.WriteLine($"вҸұпёҸ  Tiempo: {elapsed.TotalMilliseconds:F2} ms");

                        if (reservations.Any())
                        {
                            Console.WriteLine($"\nрҹ“Ӣ Detalle:");
                            foreach (var res in reservations.Take(10))
                            {
                                Console.WriteLine($"   Stock #{res.IdStock}: {res.Cantidad:F2} - UbicaciГіn {res.IdUbicacion}");
                            }
                            if (reservations.Count > 10)
                            {
                                Console.WriteLine($"   ... y {reservations.Count - 10} reservas mГЎs");
                            }
                        }

                        Console.Write("\nВҝConfirmar transacciГіn? (S/N): ");
                        if (Console.ReadLine()?.ToUpper() == "S")
                        {
                            transaction.Commit();
                            Console.WriteLine("вң… TransacciГіn confirmada");
                        }
                        else
                        {
                            transaction.Rollback();
                            Console.WriteLine("вҶ©пёҸ  TransacciГіn revertida (rollback)");
                        }
                    }
                    catch (Exception ex)
                    {
                        transaction.Rollback();
                        throw;
                    }
                }
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"вқҢ Error: {ex.Message}");
                Console.ResetColor();
            }
        }
    }
}

