using System;
using System.Data;
using System.Data.SqlClient;

namespace WMS.StockReservation.Testing.Database
{
    /// <summary>
    /// ConexiГіn a la base de datos de producciГіn SQL Server.
    /// Usa credenciales almacenadas de forma segura en Replit Secrets.
    /// </summary>
    public class ProductionDatabaseConnection : IDisposable
    {
        private readonly SqlConnection _connection;

        public ProductionDatabaseConnection()
        {
            var host = Environment.GetEnvironmentVariable("SQL_SERVER_HOST");
            var port = Environment.GetEnvironmentVariable("SQL_SERVER_PORT");
            var user = Environment.GetEnvironmentVariable("SQL_SERVER_USER");
            var password = Environment.GetEnvironmentVariable("SQL_SERVER_PASSWORD");
            var database = Environment.GetEnvironmentVariable("SQL_SERVER_DATABASE");

            if (string.IsNullOrEmpty(host) || string.IsNullOrEmpty(database))
            {
                throw new InvalidOperationException(
                    "Credenciales de SQL Server no configuradas. " +
                    "Verifica que los secrets estГ©n definidos: SQL_SERVER_HOST, SQL_SERVER_PORT, " +
                    "SQL_SERVER_USER, SQL_SERVER_PASSWORD, SQL_SERVER_DATABASE");
            }

            var connectionString = $"Server={host},{port};Database={database};" +
                                 $"User Id={user};Password={password};" +
                                 "Encrypt=True;TrustServerCertificate=True;Connect Timeout=30;";

            _connection = new SqlConnection(connectionString);
        }

        public SqlConnection GetConnection()
        {
            if (_connection.State != ConnectionState.Open)
            {
                _connection.Open();
            }
            return _connection;
        }

        public void TestConnection()
        {
            try
            {
                var conn = GetConnection();
                using (var cmd = conn.CreateCommand())
                {
                    cmd.CommandText = "SELECT @@VERSION";
                    var version = cmd.ExecuteScalar() as string;
                    Console.WriteLine($"вң… ConexiГіn exitosa a SQL Server");
                    if (!string.IsNullOrEmpty(version))
                    {
                        Console.WriteLine($"   VersiГіn: {version.Substring(0, Math.Min(80, version.Length))}...");
                    }
                }
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"вқҢ Error de conexiГіn: {ex.Message}");
                Console.ResetColor();
                throw;
            }
        }

        public DataTable ExecuteQuery(string query)
        {
            var table = new DataTable();
            using (var cmd = GetConnection().CreateCommand())
            {
                cmd.CommandText = query;
                cmd.CommandTimeout = 120;
                using (var adapter = new SqlDataAdapter(cmd))
                {
                    adapter.Fill(table);
                }
            }
            return table;
        }

        public void Dispose()
        {
            if (_connection?.State == ConnectionState.Open)
            {
                _connection.Close();
            }
            _connection?.Dispose();
        }
    }
}

