namespace WMS.StockReservation.Compatibility
{
    /// <summary>
    /// Facade de compatibilidad con VB.NET.
    /// Replica la interfaz pГәblica del mГ©todo original Reserva_Stock_From_MI3.
    /// Target: ~100 lГӯneas
    /// </summary>
    public static class StockReservationFacade
    {
        /// <summary>
        /// Punto de entrada principal compatible con VB.NET (SQL Server).
        /// Replica la firma del mГ©todo original Reserva_Stock_From_MI3.
        /// </summary>
        public static List<clsBeStock_res> Reserva_Stock_From_MI3(
            clsBeStock_res oBeStockResRequest,
            int IdProducto,
            clsBeConfigEnc oBeConfigEnc,
            SqlConnection cnnSql,
            SqlTransaction trSql,
            clsBePedidoDet oBePedidoDet = null,
            clsBeI_nav_ped_traslado_det oBeI_nav_ped_traslado_det = null,
            int Tarea_Reabasto = 0,
            bool EsDevolucion = false,
            int LineNumber = 0,
            string MachineName = null)
        {
            return Reserva_Stock_Internal(
                oBeStockResRequest, IdProducto, oBeConfigEnc,
                cnnSql, trSql, oBePedidoDet, oBeI_nav_ped_traslado_det,
                Tarea_Reabasto, EsDevolucion, LineNumber, MachineName);
        }

        /// <summary>
        /// Sobrecarga para testing con IDbConnection (soporta SQLite, SQL Server, etc.)
        /// </summary>
        public static List<clsBeStock_res> Reserva_Stock_From_MI3(
            clsBeStock_res oBeStockResRequest,
            int IdProducto,
            clsBeConfigEnc oBeConfigEnc,
            IDbConnection cnnSql,
            IDbTransaction trSql,
            clsBePedidoDet oBePedidoDet = null,
            clsBeI_nav_ped_traslado_det oBeI_nav_ped_traslado_det = null,
            int Tarea_Reabasto = 0,
            bool EsDevolucion = false,
            int LineNumber = 0,
            string MachineName = null)
        {
            return Reserva_Stock_Internal(
                oBeStockResRequest, IdProducto, oBeConfigEnc,
                cnnSql, trSql, oBePedidoDet, oBeI_nav_ped_traslado_det,
                Tarea_Reabasto, EsDevolucion, LineNumber, MachineName);
        }

        /// <summary>
        /// ImplementaciГіn interna compartida.
        /// </summary>
        private static List<clsBeStock_res> Reserva_Stock_Internal(
            clsBeStock_res oBeStockResRequest,
            int IdProducto,
            clsBeConfigEnc oBeConfigEnc,
            IDbConnection cnnSql,
            IDbTransaction trSql,
            clsBePedidoDet oBePedidoDet,
            clsBeI_nav_ped_traslado_det oBeI_nav_ped_traslado_det,
            int Tarea_Reabasto,
            bool EsDevolucion,
            int LineNumber,
            string MachineName)
        {
            // Crear factory y pipeline
            var factory = new ServiceFactory();
            var pipeline = factory.CreateReservationPipeline();

            // Construir contexto
            var context = new ReservationContext
            {
                Request = oBeStockResRequest,
                ProductId = IdProducto,
                Configuration = oBeConfigEnc,
                Connection = cnnSql,
                Transaction = trSql,
                PedidoDet = oBePedidoDet,
                TrasladoDet = oBeI_nav_ped_traslado_det,
                TareaReabasto = Tarea_Reabasto,
                EsDevolucion = EsDevolucion,
                LineNumber = LineNumber,
                MachineName = MachineName ?? Environment.MachineName
            };

            // Ejecutar pipeline
            var result = pipeline.Execute(context);

            // Verificar resultado
            if (!result.Success && context.HasError)
            {
                throw new Exception($"Error en reserva de stock: {context.ErrorMessage}");
            }

            // Retornar reservas creadas
            return result.Reservations;
        }

        /// <summary>
        /// VersiГіn simplificada para casos simples (sin pedidos/traslados).
        /// </summary>
        public static List<clsBeStock_res> ReservarStock(
            int bodegaId,
            int productoId,
            double cantidad,
            int presentacionId,
            clsBeConfigEnc configuracion,
            SqlConnection connection,
            SqlTransaction transaction = null)
        {
            var request = new clsBeStock_res
            {
                IdBodega = bodegaId,
                IdProducto = productoId,
                IdPresentacion = presentacionId,
                Cantidad = cantidad
            };

            return Reserva_Stock_From_MI3(
                request,
                productoId,
                configuracion,
                connection,
                transaction);
        }
    }
}

