## SERVICE FACTORY: ConstrucciГіn DinГЎmica de Cadena

```csharp
public interface IServiceFactory
{
    IReservationPipeline CreateReservationPipeline();

    /// вң… NUEVO: Crear cadena dinГЎmicamente segГәn StartingPoint
    IReservationHandler BuildHandlerChain(
        int startingPoint,
        ReservationContext context,
        IReservationLogger logger);
}

public class ServiceFactory : IServiceFactory
{
    // Singleton para servicios sin estado
    private readonly IReservationLogger _logger = new ReservationLogger();
    private readonly IQuantityConverter _quantityConverter = new QuantityConverter();
    private readonly IDecimalQuantityHandler _decimalHandler = new DecimalQuantityHandler();
    private readonly IDateExpirationCalculator _dateCalculator = new DateExpirationCalculator();
    private readonly IPresentationExplosionService _explosionService;
    private readonly IStockReservationBuilder _builder = new StockReservationBuilder();

    public ServiceFactory()
    {
        _explosionService = new PresentationExplosionService(_quantityConverter, _decimalHandler);
    }

    public IReservationPipeline CreateReservationPipeline()
    {
        var steps = new IPipelineStep[]
        {
            new ValidationStep(_logger),
            new EntityLoadingStep(_logger),
            new StockQueryStep(_logger),
            new DateCalculationStep(_dateCalculator, _logger),
            new ReservationLoopStep(this, _logger), // вң… Inyectar factory
            new PostProcessingStep(_logger)
        };

        return new PipelineExecutor(steps, _logger);
    }

    /// <summary>
    /// вң… CONSTRUIR CADENA DINГҒMICAMENTE segГәn StartingPoint.
    /// Esto se llama en CADA iteraciГіn del loop.
    /// </summary>
    public IReservationHandler BuildHandlerChain(
        int startingPoint,
        ReservationContext context,
        IReservationLogger logger)
    {
        // Crear handlers frescos (cada uno ~100-150 lГӯneas)
        var completeHandler = new CompletePackagesHandler(_builder, logger);
        var incompleteHandler = new IncompletePackagesHandler(_builder, logger);
        var pickingHandler = new PickingZoneHandler(_builder, logger);
        var nonPickingHandler = new NonPickingZoneHandler(_builder, logger);
        var umBasHandler = new UMBasExplosionHandler(_explosionService, _builder, logger);

        // Conectar la cadena segГәn StartingPoint
        switch (startingPoint)
        {
            case 1: // INICIAR_EN_1: Pallets completos
                completeHandler.SetNext(incompleteHandler);
                incompleteHandler.SetNext(pickingHandler);
                pickingHandler.SetNext(nonPickingHandler);
                nonPickingHandler.SetNext(umBasHandler);
                return completeHandler;

            case 2: // INICIAR_EN_2: Pallets incompletos
                incompleteHandler.SetNext(pickingHandler);
                pickingHandler.SetNext(nonPickingHandler);
                nonPickingHandler.SetNext(umBasHandler);
                return incompleteHandler;

            case 3: // INICIAR_EN_3: Zona Picking
                pickingHandler.SetNext(nonPickingHandler);
                nonPickingHandler.SetNext(umBasHandler);
                return pickingHandler;

            case 4: // INICIAR_EN_4: AlmacГ©n (zonas no-picking)
                // Si llegamos aquГӯ es porque WorkingStockList fue recargada
                nonPickingHandler.SetNext(umBasHandler);
                return nonPickingHandler;

            default: // Caso 0: Гҡltima lista (general)
                nonPickingHandler.SetNext(umBasHandler);
                return nonPickingHandler;
        }
    }
}
