```csharp
public class CompletePackagesHandler : BaseReservationHandler
{
    protected override HandlerResult ProcessReservation(ReservationContext context)
    {
        _logger.LogCheckpoint("#MI3_HANDLER_COMPLETE_START");

        var result = new HandlerResult { ... };
        var completePallets = context.StockListNonPickingZones
            .Where(s => s.Pallet_Completo && !s.UbicacionPicking && ...)
            .OrderBy(s => s.Fecha_vence)
            .ToList();

        _logger.LogInfo($"Pallets completos disponibles: {completePallets.Count}");

        foreach (var stock in completePallets)
        {
            if (context.PendingQuantity <= 0.000001) break;

            double toReserve = Math.Min(context.PendingQuantity, stock.Cantidad);

            // Determinar caso especГӯfico
            string caseCode = DetermineCaseCode(toReserve, stock.Cantidad, context);

            var reservation = _builder.BuildReservation(stock, context, toReserve);
            reservation.IdStockRes = clsLnStock_res.MaxID(...) + 1;

            clsLnStock_res.Insertar(reservation, context.Connection, context.Transaction);

            // вң… LOGGING DETALLADO (mapea a Agregar_Log_Reserva original)
            string logMessage = 
                $"{caseCode} | " +
                $"FechaMin: {context.GlobalMinimumExpirationDate:yyyy-MM-dd} | " +
                $"FechaRes: {reservation.Fecha_vence:yyyy-MM-dd} | " +
                $"Lote: {reservation.Lote} | " +
                $"UbicaciГіn: {reservation.IdUbicacion} | " +
                $"Cantidad: {toReserve:F6} | " +
                $"LicPlate: {stock.Lic_plate}";

            _logger.LogReservation(reservation, caseCode, logMessage);

            // вң… TAMBIГүN insertar en tabla de log (compatible con original)
            clsLnTrans_pe_det_log_reserva.Agregar_Log_Reserva(
                reservation,
                caseCode,
                logMessage);

            result.Reservations.Add(reservation);
            result.ReservedQuantity += toReserve;
            result.CaseCode += (result.CaseCode == "" ? "" : ", ") + caseCode;

            _logger.LogCheckpoint($"#MI3_HANDLER_COMPLETE_RESERVED | Cant: {toReserve:F6} | Caso: {caseCode}");

            // Actualizar stock
            stock.Cantidad -= toReserve;
        }

        // Restar de listas
        clsLnStock_res.Restar_Stock_Reservado(
            context.StockListNonPickingZones,
            context.Configuration,
            context.Connection,
            context.Transaction);

        _logger.LogCheckpoint($"#MI3_HANDLER_COMPLETE_END | TotalReservado: {result.ReservedQuantity:F6}");
        return result;
    }

    private string DetermineCaseCode(double toReserve, double available, ReservationContext context)
    {
        if (Math.Abs(toReserve - available) < 0.000001)
        {
            // ReservГі todo el pallet
            return context.Request.IdPresentacion == 0 
                ? "CASO_#03_COMPLETE_EXPLOS" 
                : "CASO_#01_COMPLETE_FULL";
        }
        else
        {
            // Reserva parcial
            return "CASO_#02_COMPLETE_PARTIAL";
        }
    }
}
