using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SQLite;
using System.Linq;
using WMS.StockReservation.Core.Domain;

namespace WMS.StockReservation.Testing.Mocks
{
    /// <summary>
    /// Mock de la capa de acceso a datos (simula clsLnStock, clsLnProducto, etc.)
    /// Lee datos desde SQLite en lugar de SQL Server.
    /// </summary>
    public static class clsLnStock
    {
        public static List<clsBeStock> lStock(
            clsBeStock_res request,
            clsBeProducto producto,
            int diasVencimiento,
            clsBeConfigEnc config,
            IDbConnection connection,
            IDbTransaction transaction,
            bool soloPickingZone,
            bool soloNonPickingZone,
            int tareaReabasto,
            bool esDevolucion)
        {
            var stockList = new List<clsBeStock>();

            string sql = @"
                SELECT s.*, 
                       u.EsPicking as UbicacionPicking,
                       u.Nivel as UbicacionNivel,
                       u.Codigo as UbicacionCodigo,
                       CASE 
                           WHEN s.uds_lic_plate IS NOT NULL AND s.cantidad >= s.uds_lic_plate 
                           THEN 1 
                           ELSE 0 
                       END as Pallet_Completo
                FROM stock s
                INNER JOIN bodega_ubicacion u ON s.IdUbicacion = u.IdUbicacion
                WHERE s.IdBodega = @IdBodega
                  AND s.IdProductoBodega = @IdProductoBodega
                  AND s.activo = 1
                  AND s.cantidad > 0";

            // Filtrar por presentaciГіn si aplica
            if (request.IdPresentacion.HasValue && request.IdPresentacion.Value > 0)
            {
                sql += " AND s.IdPresentacion = @IdPresentacion";
            }
            else
            {
                // UMBas: sin presentaciГіn
                sql += " AND (s.IdPresentacion IS NULL OR s.IdPresentacion = 0)";
            }

            // Filtrar por zona
            if (soloPickingZone)
            {
                sql += " AND u.EsPicking = 1";
            }
            else if (soloNonPickingZone)
            {
                sql += " AND u.EsPicking = 0";
            }

            // Ordenar segГәn estrategia
            sql += " ORDER BY s.fecha_vence ASC, s.lic_plate ASC";

            using (var cmd = connection.CreateCommand())
            {
                cmd.CommandText = sql;
                cmd.Transaction = transaction;

                AddParameter(cmd, "@IdBodega", request.IdBodega);
                AddParameter(cmd, "@IdProductoBodega", producto.IdProducto); // Simplificado

                if (request.IdPresentacion.HasValue && request.IdPresentacion.Value > 0)
                {
                    AddParameter(cmd, "@IdPresentacion", request.IdPresentacion.Value);
                }

                using (var reader = cmd.ExecuteReader())
                {
                    while (reader.Read())
                    {
                        stockList.Add(MapStockFromReader(reader));
                    }
                }
            }

            return stockList;
        }

        private static clsBeStock MapStockFromReader(IDataReader reader)
        {
            return new clsBeStock
            {
                IdStock = Convert.ToInt32(reader["IdStock"]),
                IdBodega = Convert.ToInt32(reader["IdBodega"]),
                IdProductoBodega = Convert.ToInt32(reader["IdProductoBodega"]),
                IdPropietarioBodega = Convert.ToInt32(reader["IdPropietarioBodega"]),
                IdProductoEstado = Convert.ToInt32(reader["IdProductoEstado"]),
                IdPresentacion = reader["IdPresentacion"] != DBNull.Value 
                    ? Convert.ToInt32(reader["IdPresentacion"]) : (int?)null,
                IdUnidadMedida = reader["IdUnidadMedida"] != DBNull.Value 
                    ? Convert.ToInt32(reader["IdUnidadMedida"]) : (int?)null,
                IdUbicacion = Convert.ToInt32(reader["IdUbicacion"]),
                Lote = reader["lote"].ToString(),
                Lic_plate = reader["lic_plate"]?.ToString() ?? "",
                Cantidad = Convert.ToDouble(reader["cantidad"]),
                Fecha_ingreso = DateTime.Parse(reader["fecha_ingreso"].ToString()),
                Fecha_vence = DateTime.Parse(reader["fecha_vence"].ToString()),
                Uds_lic_plate = reader["uds_lic_plate"] != DBNull.Value 
                    ? Convert.ToDouble(reader["uds_lic_plate"]) : (double?)null,
                Activo = Convert.ToBoolean(reader["activo"]),

                // Propiedades calculadas
                UbicacionPicking = Convert.ToBoolean(reader["UbicacionPicking"]),
                UbicacionNivel = Convert.ToInt32(reader["UbicacionNivel"]),
                UbicacionCodigo = reader["UbicacionCodigo"].ToString(),
                Pallet_Completo = Convert.ToBoolean(reader["Pallet_Completo"])
            };
        }

        private static void AddParameter(IDbCommand cmd, string name, object value)
        {
            var param = cmd.CreateParameter();
            param.ParameterName = name;
            param.Value = value ?? DBNull.Value;
            cmd.Parameters.Add(param);
        }
    }

    public static class clsLnStock_res
    {
        public static void Restar_Stock_Reservado(
            List<clsBeStock> stockList,
            clsBeConfigEnc config,
            IDbConnection connection,
            IDbTransaction transaction)
        {
            if (stockList == null || stockList.Count == 0) return;

            var stockIds = string.Join(",", stockList.Select(s => s.IdStock));

            string sql = $@"
                SELECT IdStock, SUM(cantidad) as CantidadReservada
                FROM stock_res
                WHERE IdStock IN ({stockIds})
                GROUP BY IdStock";

            using (var cmd = connection.CreateCommand())
            {
                cmd.CommandText = sql;
                cmd.Transaction = transaction;

                using (var reader = cmd.ExecuteReader())
                {
                    while (reader.Read())
                    {
                        int idStock = Convert.ToInt32(reader["IdStock"]);
                        double cantidadReservada = Convert.ToDouble(reader["CantidadReservada"]);

                        var stock = stockList.FirstOrDefault(s => s.IdStock == idStock);
                        if (stock != null)
                        {
                            stock.Cantidad = Math.Max(0, stock.Cantidad - cantidadReservada);
                        }
                    }
                }
            }
        }

        public static int Insert(
            clsBeStock_res reservation,
            IDbConnection connection,
            IDbTransaction transaction)
        {
            string sql = @"
                INSERT INTO stock_res (
                    IdStockRes, IdTransaccion, Indicador, IdPedidoDet, IdStock,
                    IdPropietarioBodega, IdProductoBodega, IdProductoEstado,
                    IdPresentacion, IdUnidadMedida, IdUbicacion, lic_plate,
                    cantidad, fecha_ingreso, fecha_vence, IdBodega, Linea, Equipo,
                    user_agr, fec_agr
                ) VALUES (
                    @IdStockRes, @IdTransaccion, @Indicador, @IdPedidoDet, @IdStock,
                    @IdPropietarioBodega, @IdProductoBodega, @IdProductoEstado,
                    @IdPresentacion, @IdUnidadMedida, @IdUbicacion, @lic_plate,
                    @cantidad, @fecha_ingreso, @fecha_vence, @IdBodega, @Linea, @Equipo,
                    @user_agr, @fec_agr
                )";

            using (var cmd = connection.CreateCommand())
            {
                cmd.CommandText = sql;
                cmd.Transaction = transaction;

                AddParameter(cmd, "@IdStockRes", reservation.IdStockRes);
                AddParameter(cmd, "@IdTransaccion", reservation.IdTransaccion);
                AddParameter(cmd, "@Indicador", reservation.Indicador);
                AddParameter(cmd, "@IdPedidoDet", reservation.IdPedidoDet);
                AddParameter(cmd, "@IdStock", reservation.IdStock);
                AddParameter(cmd, "@IdPropietarioBodega", reservation.IdPropietarioBodega);
                AddParameter(cmd, "@IdProductoBodega", reservation.IdProductoBodega);
                AddParameter(cmd, "@IdProductoEstado", reservation.IdProductoEstado);
                AddParameter(cmd, "@IdPresentacion", reservation.IdPresentacion);
                AddParameter(cmd, "@IdUnidadMedida", reservation.IdUnidadMedida);
                AddParameter(cmd, "@IdUbicacion", reservation.IdUbicacion);
                AddParameter(cmd, "@lic_plate", reservation.Lic_plate);
                AddParameter(cmd, "@cantidad", reservation.Cantidad);
                AddParameter(cmd, "@fecha_ingreso", reservation.Fecha_ingreso);
                AddParameter(cmd, "@fecha_vence", reservation.Fecha_vence);
                AddParameter(cmd, "@IdBodega", reservation.IdBodega);
                AddParameter(cmd, "@Linea", reservation.Linea);
                AddParameter(cmd, "@Equipo", reservation.Equipo);
                AddParameter(cmd, "@user_agr", "TEST");
                AddParameter(cmd, "@fec_agr", DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss"));

                return cmd.ExecuteNonQuery();
            }
        }

        private static void AddParameter(IDbCommand cmd, string name, object value)
        {
            var param = cmd.CreateParameter();
            param.ParameterName = name;
            param.Value = value ?? DBNull.Value;
            cmd.Parameters.Add(param);
        }
    }

