using System;
using System.Collections.Generic;
using System.Data;
using System.IO;
using System.Linq;
using System.Text;

namespace WMS.StockReservation.Testing.Database
{
    /// <summary>
    /// Importa datos reales desde archivos CSV a la base de datos de testing.
    /// </summary>
    public class RealDataImporter
    {
        private readonly IDbConnection _connection;

        public RealDataImporter(IDbConnection connection)
        {
            _connection = connection ?? throw new ArgumentNullException(nameof(connection));
        }

        public ImportResult ImportFromCSV(string stockCsvPath, string stockResCsvPath)
        {
            var result = new ImportResult();

            try
            {
                // Importar stock
                result.StockRecords = ImportStockCSV(stockCsvPath);

                // Importar reservas
                result.ReservationRecords = ImportStockResCSV(stockResCsvPath);

                result.Success = true;
            }
            catch (Exception ex)
            {
                result.Success = false;
                result.ErrorMessage = ex.Message;
            }

            return result;
        }

        private int ImportStockCSV(string csvPath)
        {
            if (!File.Exists(csvPath))
                throw new FileNotFoundException($"Archivo CSV no encontrado: {csvPath}");

            int count = 0;
            var lines = File.ReadAllLines(csvPath, Encoding.GetEncoding("ISO-8859-1"));

            // Saltar header
            for (int i = 1; i < lines.Length; i++)
            {
                var line = lines[i];
                if (string.IsNullOrWhiteSpace(line)) continue;

                var fields = line.Split(';');
                if (fields.Length < 33) continue;

                try
                {
                    var sql = $@"
                        INSERT INTO stock (
                            IdBodega, IdStock, IdPropietarioBodega, IdProductoBodega, IdProductoEstado,
                            IdPresentacion, IdUnidadMedida, IdUbicacion, IdUbicacion_anterior,
                            lote, lic_plate, cantidad, fecha_ingreso, fecha_vence, uds_lic_plate,
                            user_agr, fec_agr, user_mod, fec_mod, activo
                        ) VALUES (
                            {ParseInt(fields[0])}, {ParseInt(fields[1])}, {ParseInt(fields[2])}, 
                            {ParseInt(fields[3])}, {ParseInt(fields[4])},
                            {ParseNullableInt(fields[5])}, {ParseNullableInt(fields[6])}, 
                            {ParseInt(fields[7])}, {ParseNullableInt(fields[8])},
                            '{EscapeString(fields[14])}', {ParseNullableString(fields[15])}, 
                            {ParseDouble(fields[17])}, '{ParseDate(fields[18])}', '{ParseDate(fields[19])}', 
                            {ParseNullableDouble(fields[20])},
                            '{EscapeString(fields[24])}', '{ParseDate(fields[25])}', 
                            '{EscapeString(fields[26])}', '{ParseDate(fields[27])}', {ParseInt(fields[28])}
                        )";

                    using (var cmd = _connection.CreateCommand())
                    {
                        cmd.CommandText = sql;
                        cmd.ExecuteNonQuery();
                        count++;
                    }
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"Error importando lГӯnea {i}: {ex.Message}");
                }
            }

            return count;
        }

        private int ImportStockResCSV(string csvPath)
        {
            if (!File.Exists(csvPath))
                throw new FileNotFoundException($"Archivo CSV no encontrado: {csvPath}");

            int count = 0;
            var lines = File.ReadAllLines(csvPath, Encoding.GetEncoding("ISO-8859-1"));

            // Saltar header
            for (int i = 1; i < lines.Length; i++)
            {
                var line = lines[i];
                if (string.IsNullOrWhiteSpace(line)) continue;

                var fields = line.Split(';');
                if (fields.Length < 34) continue;

                try
                {
                    var sql = $@"
                        INSERT INTO stock_res (
                            IdStockRes, IdTransaccion, Indicador, IdPedidoDet, IdStock,
                            IdPropietarioBodega, IdProductoBodega, IdProductoEstado,
                            IdPresentacion, IdUnidadMedida, IdUbicacion, lic_plate,
                            cantidad, fecha_ingreso, fecha_vence, IdBodega
                        ) VALUES (
                            {ParseInt(fields[0])}, {ParseInt(fields[1])}, {ParseNullableString(fields[2])}, 
                            {ParseInt(fields[3])}, {ParseInt(fields[4])},
                            {ParseInt(fields[5])}, {ParseInt(fields[6])}, {ParseNullableInt(fields[7])},
                            {ParseNullableInt(fields[8])}, {ParseNullableInt(fields[9])}, 
                            {ParseInt(fields[10])}, {ParseNullableString(fields[14])},
                            {ParseDouble(fields[16])}, '{ParseDate(fields[19])}', '{ParseDate(fields[20])}', 
                            {ParseInt(fields[33])}
                        )";

                    using (var cmd = _connection.CreateCommand())
                    {
                        cmd.CommandText = sql;
                        cmd.ExecuteNonQuery();
                        count++;
                    }
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"Error importando reserva lГӯnea {i}: {ex.Message}");
                }
            }

            return count;
        }

        private int ParseInt(string value)
        {
            if (string.IsNullOrWhiteSpace(value) || value == "NULL")
                return 0;
            return int.Parse(value);
        }

        private string ParseNullableInt(string value)
        {
            if (string.IsNullOrWhiteSpace(value) || value == "NULL")
                return "NULL";
            return value;
        }

        private double ParseDouble(string value)
        {
            if (string.IsNullOrWhiteSpace(value) || value == "NULL")
                return 0;
            return double.Parse(value.Replace(",", "."));
        }

        private string ParseNullableDouble(string value)
        {
            if (string.IsNullOrWhiteSpace(value) || value == "NULL")
                return "NULL";
            return value.Replace(",", ".");
        }

        private string ParseNullableString(string value)
        {
            if (string.IsNullOrWhiteSpace(value) || value == "NULL" || value == "0")
                return "NULL";
            return $"'{EscapeString(value)}'";
        }

        private string ParseDate(string value)
        {
            if (string.IsNullOrWhiteSpace(value) || value == "NULL")
                return DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");

            if (DateTime.TryParse(value, out DateTime date))
                return date.ToString("yyyy-MM-dd HH:mm:ss");

            return DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
        }

        private string EscapeString(string value)
        {
            if (string.IsNullOrEmpty(value))
                return string.Empty;
            return value.Replace("'", "''");
        }
    }

    public class ImportResult
    {
        public bool Success { get; set; }
        public int StockRecords { get; set; }
        public int ReservationRecords { get; set; }
        public string ErrorMessage { get; set; }

        public override string ToString()
        {
            if (!Success)
                return $"вқҢ Error: {ErrorMessage}";

            return $@"вң… ImportaciГіn exitosa:
   - Stock: {StockRecords:N0} registros
   - Reservas: {ReservationRecords:N0} registros";
        }
    }
}

