using System;
using System.Data;
using System.Data.SQLite;
using System.IO;

namespace WMS.StockReservation.Testing.Database
{
    /// <summary>
    /// GestiГіn de conexiГіn a base de datos SQLite para testing.
    /// </summary>
    public class TestDatabaseConnection : IDisposable
    {
        private SQLiteConnection _connection;
        private readonly string _databasePath;
        private readonly bool _useInMemory;

        public TestDatabaseConnection(bool useInMemory = true, string databasePath = null)
        {
            _useInMemory = useInMemory;
            _databasePath = databasePath ?? Path.Combine(
                AppDomain.CurrentDomain.BaseDirectory, 
                "TestDatabase.db");
        }

        public SQLiteConnection GetConnection()
        {
            if (_connection != null && _connection.State == ConnectionState.Open)
                return _connection;

            string connectionString = _useInMemory
                ? "Data Source=:memory:;Version=3;New=True;"
                : $"Data Source={_databasePath};Version=3;New=True;";

            _connection = new SQLiteConnection(connectionString);
            _connection.Open();

            return _connection;
        }

        public void InitializeSchema()
        {
            var schemaPath = Path.Combine(
                AppDomain.CurrentDomain.BaseDirectory,
                "Database",
                "schema.sql");

            if (!File.Exists(schemaPath))
            {
                // Si no existe el archivo, usar schema embebido
                ExecuteSchemaFromResource();
                return;
            }

            string schema = File.ReadAllText(schemaPath);
            ExecuteNonQuery(schema);
        }

        private void ExecuteSchemaFromResource()
        {
            // Schema mГӯnimo si no existe el archivo
            string minimalSchema = @"
                CREATE TABLE IF NOT EXISTS stock (
                    IdStock INTEGER PRIMARY KEY,
                    IdBodega INTEGER NOT NULL,
                    IdProductoBodega INTEGER NOT NULL,
                    IdPropietarioBodega INTEGER NOT NULL,
                    IdProductoEstado INTEGER NOT NULL,
                    IdPresentacion INTEGER NULL,
                    IdUnidadMedida INTEGER NULL,
                    IdUbicacion INTEGER NOT NULL,
                    lote TEXT NOT NULL DEFAULT '',
                    lic_plate TEXT NULL,
                    cantidad REAL NOT NULL DEFAULT 0,
                    fecha_ingreso TEXT NOT NULL,
                    fecha_vence TEXT NOT NULL,
                    user_agr TEXT NOT NULL,
                    fec_agr TEXT NOT NULL,
                    user_mod TEXT NOT NULL,
                    fec_mod TEXT NOT NULL,
                    activo INTEGER NOT NULL DEFAULT 1,
                    CHECK (cantidad > 0)
                );

                CREATE TABLE IF NOT EXISTS stock_res (
                    IdStockRes INTEGER PRIMARY KEY,
                    IdStock INTEGER NOT NULL,
                    IdPedidoDet INTEGER NOT NULL,
                    IdBodega INTEGER NOT NULL,
                    IdProductoBodega INTEGER NOT NULL,
                    IdPropietarioBodega INTEGER NOT NULL,
                    IdPresentacion INTEGER NULL,
                    IdUbicacion INTEGER NOT NULL,
                    lic_plate TEXT NULL,
                    cantidad REAL NOT NULL,
                    CHECK (cantidad > 0)
                );
            ";

            ExecuteNonQuery(minimalSchema);
        }

        public void ExecuteNonQuery(string sql)
        {
            using (var command = new SQLiteCommand(sql, GetConnection()))
            {
                command.ExecuteNonQuery();
            }
        }

        public DataTable ExecuteQuery(string sql)
        {
            using (var command = new SQLiteCommand(sql, GetConnection()))
            using (var adapter = new SQLiteDataAdapter(command))
            {
                var table = new DataTable();
                adapter.Fill(table);
                return table;
            }
        }

        public void ClearAllTables()
        {
            ExecuteNonQuery("DELETE FROM stock_res");
            ExecuteNonQuery("DELETE FROM stock");
            ExecuteNonQuery("DELETE FROM pedido_det");
            ExecuteNonQuery("DELETE FROM producto_presentacion");
            ExecuteNonQuery("DELETE FROM producto_bodega");
            ExecuteNonQuery("DELETE FROM producto");
            ExecuteNonQuery("DELETE FROM bodega_ubicacion");
            ExecuteNonQuery("DELETE FROM bodega");
            ExecuteNonQuery("DELETE FROM config_enc");
            ExecuteNonQuery("DELETE FROM unidad_medida");
            ExecuteNonQuery("DELETE FROM producto_estado");
            ExecuteNonQuery("DELETE FROM propietario_bodega");
        }

        public void Dispose()
        {
            if (_connection != null)
            {
                if (_connection.State == ConnectionState.Open)
                    _connection.Close();

                _connection.Dispose();
                _connection = null;
            }

            if (!_useInMemory && File.Exists(_databasePath))
            {
                try
                {
                    File.Delete(_databasePath);
                }
                catch
                {
                    // Ignorar errores al eliminar
                }
            }
        }
    }
}

