/// </summary>
public class StockReservationFacade
{
    private static readonly Lazy<IServiceFactory> _factory = 
        new Lazy<IServiceFactory>(() => new ServiceFactory());

    /// <summary>
    /// Firma original VB.NET preservada
    /// </summary>
    public static bool Reserva_Stock_From_MI3(
        clsBeStock_res pStockResSolicitud,
        int IdProducto,
        clsBeConfigEnc pBeConfigEnc,
        SqlConnection lConnection,
        SqlTransaction ltransaction,
        out List<clsBeStock_res> pListStockResOUT,
        clsBePedidoDet BePedidoDet = null,
        clsBeI_nav_ped_traslado_det pBeTrasladoDet = null,
        int pTarea_Reabasto = 0,
        bool pEs_Devolucion = false,
        int No_Linea = 0,
        string MaquinaQueSolicita = "")
    {
        var pipeline = _factory.Value.CreateReservationPipeline();
        var context = new ReservationContext
        {
