/// <summary>
/// Factory sin DI para crear servicios desde cГіdigo VB.NET legacy
/// </summary>
public interface IServiceFactory
{
    IReservationPipeline CreateReservationPipeline();
}

public class ServiceFactory : IServiceFactory
{
    public IReservationPipeline CreateReservationPipeline()
    {
        // Crear servicios manualmente (sin DI container)
        var logger = new ReservationLogger();
        var quantityConverter = new QuantityConverter();
        var decimalHandler = new DecimalQuantityHandler();
        var dateCalculator = new DateExpirationCalculator();
        var explosionService = new PresentationExplosionService(quantityConverter, decimalHandler);
        var reservationBuilder = new StockReservationBuilder();

        // Crear handlers de la cadena
        var handlers = CreateHandlerChain(logger, quantityConverter, decimalHandler, 
                                          reservationBuilder, explosionService);

        // Crear pipeline steps
        var validationStep = new ValidationStep(logger);
        var entityLoadingStep = new EntityLoadingStep(logger);
        var stockQueryStep = new StockQueryStep(logger);
        var dateCalcStep = new DateCalculationStep(dateCalculator, logger);
        var reservationLoopStep = new ReservationLoopStep(handlers, logger);
        var postProcessStep = new PostProcessingStep(logger);

        return new PipelineExecutor(new IPipelineStep[]
        {
            validationStep,
            entityLoadingStep,
            stockQueryStep,
            dateCalcStep,
            reservationLoopStep,
            postProcessStep
        }, logger);
    }

    private IReservationHandler CreateHandlerChain(/* services */)
    {
        // Chain: Complete вҶ’ Incomplete вҶ’ Picking вҶ’ NonPicking вҶ’ UMBas
        var umBasHandler = new UMBasExplosionHandler(explosionService, logger);
        var nonPickingHandler = new NonPickingZoneHandler(reservationBuilder, logger);
        nonPickingHandler.SetNext(umBasHandler);

        var pickingHandler = new PickingZoneHandler(reservationBuilder, logger);
        pickingHandler.SetNext(nonPickingHandler);

        var incompleteHandler = new IncompletePackagesHandler(reservationBuilder, logger);
        incompleteHandler.SetNext(pickingHandler);

        var completeHandler = new CompletePackagesHandler(reservationBuilder, logger);
        completeHandler.SetNext(incompleteHandler);

        return completeHandler; // Retorna el primero en la cadena
    }
}
