```csharp
/// <summary>
/// Pipeline ejecuta pasos secuenciales pequeГұos.
/// Cada paso modifica el contexto compartido.
/// Target: ~60 lГӯneas
/// </summary>
public interface IReservationPipeline
{
    ReservationResult Execute(ReservationContext context);
}

public class PipelineExecutor : IReservationPipeline
{
    private readonly IPipelineStep[] _steps;
    private readonly IReservationLogger _logger;

    public PipelineExecutor(IPipelineStep[] steps, IReservationLogger logger)
    {
        _steps = steps;
        _logger = logger;
    }

    public ReservationResult Execute(ReservationContext context)
    {
        _logger.LogInfo("=== INICIO PIPELINE RESERVA ===");

        foreach (var step in _steps)
        {
            _logger.LogInfo($"Ejecutando: {step.GetType().Name}");
            step.Execute(context);

            if (context.HasError)
            {
                _logger.LogError($"Error en {step.GetType().Name}: {context.ErrorMessage}");
                break;
            }

            // Salida temprana si se completГі
            if (context.IsQuantityFullyReserved())
            {
                _logger.LogInfo("Cantidad completamente reservada. Fin pipeline.");
                break;
            }
        }

        _logger.LogInfo("=== FIN PIPELINE RESERVA ===");

        return new ReservationResult
        {
            Success = !context.HasError && context.IsQuantityFullyReserved(),
            Reservations = context.CreatedReservations,
            RemainingQuantity = context.PendingQuantity,
            Messages = _logger.GetMessages()
        };
    }
}

/// <summary>
/// Interfaz para cada paso del pipeline
/// </summary>
public interface IPipelineStep
{
    void Execute(ReservationContext context);
}

// ========== PASOS DEL PIPELINE (Cada uno <150 lГӯneas) ==========

/// <summary>
/// Paso 1: ValidaciГіn de parГЎmetros y configuraciГіn
/// Target: ~50 lГӯneas
/// </summary>
public class ValidationStep : IPipelineStep
{
    private readonly IReservationLogger _logger;

    public ValidationStep(IReservationLogger logger) => _logger = logger;

    public void Execute(ReservationContext context)
    {
        _logger.LogCheckpoint("#MI3_VALIDATION_START");

        if (context.Request == null)
            throw new ArgumentNullException(nameof(context.Request));

        if (context.ProductId <= 0)
            throw new ArgumentException("ProductId invГЎlido");

        if (context.Configuration == null)
            throw new ArgumentNullException(nameof(context.Configuration));

        if (context.Request.Cantidad <= 0)
            throw new ArgumentException("Cantidad debe ser > 0");

        // Inicializar valores en contexto
        context.PendingQuantity = context.Request.Cantidad;
        context.CreatedReservations = new List<clsBeStock_res>();
        context.ProcessStateFlags = new List<int>();
        context.CachedLocations = new List<clsBeBodega_ubicacion>();
        context.CachedPresentations = new List<clsBeProducto_Presentacion>();

        _logger.LogCheckpoint($"#MI3_VALIDATION_OK - Cantidad Solicitada: {context.PendingQuantity}");
    }
}

/// <summary>
/// Paso 2: Carga de entidades (Bodega, Producto, Presentaciones)
/// Target: ~80 lГӯneas
/// </summary>
public class EntityLoadingStep : IPipelineStep
{
    private readonly IReservationLogger _logger;

    public EntityLoadingStep(IReservationLogger logger) => _logger = logger;

    public void Execute(ReservationContext context)
    {
        _logger.LogCheckpoint("#MI3_ENTITY_LOADING_START");

        // Cargar Bodega
        context.Bodega = clsLnBodega.Get_Single_By_IdBodega(
            context.Request.IdBodega,
            context.Connection,
            context.Transaction);

        if (context.Bodega == null)
        {
            context.SetError("Bodega no encontrada");
            return;
        }

        // Cargar Producto
        context.Product = clsLnProducto.Get_Single_By_IdProducto(
            context.ProductId,
            context.Connection,
            context.Transaction);

        if (context.Product == null)
        {
            context.SetError($"Producto {context.ProductId} no encontrado");
            return;
        }

        // Cargar PresentaciГіn por defecto
        context.DefaultPresentation = clsLnProducto_presentacion
            .Get_Presentacion_Defecto_By_IdProducto(
                context.ProductId,
                context.Connection,
                context.Transaction);

        if (context.DefaultPresentation != null)
        {
            context.CachedPresentations.Add(context.DefaultPresentation);
        }

        _logger.LogCheckpoint($"#MI3_ENTITY_LOADING_OK - Producto: {context.Product.Codigo}, " +
                            $"Bodega: {context.Bodega.Codigo}");
    }
}

/// <summary>
/// Paso 3: Consulta y preparaciГіn de stock disponible por zonas
/// Target: ~120 lГӯneas
/// </summary>
public class StockQueryStep : IPipelineStep
{
    private readonly IReservationLogger _logger;

    public StockQueryStep(IReservationLogger logger) => _logger = logger;

    public void Execute(ReservationContext context)
    {
        _logger.LogCheckpoint("#MI3_STOCK_QUERY_START");

        int diasVencimiento = context.Configuration.Dias_diferencia_fecha_vencimiento;

        // Consultar stock en zona Picking
        context.StockListPickingZone = clsLnStock.lStock(
            context.Request,
            context.Product,
            diasVencimiento,
            context.Configuration,
            context.Connection,
            context.Transaction,
            soloPickingZone: true,
            soloNonPickingZone: false,
            context.TareaReabasto,
            context.EsDevolucion);

        // Restar stock ya reservado
        if (context.StockListPickingZone != null && context.StockListPickingZone.Count > 0)
        {
            clsLnStock_res.Restar_Stock_Reservado(
                context.StockListPickingZone,
                context.Configuration,
                context.Connection,
                context.Transaction);

            context.StockListPickingZone = context.StockListPickingZone
                .Where(s => s.Cantidad > 0)
                .ToList();
        }

        // Consultar stock en zonas NO Picking
        context.StockListNonPickingZones = clsLnStock.lStock(
            context.Request,
            context.Product,
            diasVencimiento,
            context.Configuration,
            context.Connection,
            context.Transaction,
            soloPickingZone: false,
            soloNonPickingZone: true,
            context.TareaReabasto,
            context.EsDevolucion);

        if (context.StockListNonPickingZones != null && context.StockListNonPickingZones.Count > 0)
        {
            clsLnStock_res.Restar_Stock_Reservado(
                context.StockListNonPickingZones,
                context.Configuration,
                context.Connection,
                context.Transaction);

            context.StockListNonPickingZones = context.StockListNonPickingZones
                .Where(s => s.Cantidad > 0)
                .ToList();
        }

        // Unificar lista de trabajo inicial
        context.WorkingStockList = new List<clsBeStock>();
        if (context.StockListPickingZone != null)
            context.WorkingStockList.AddRange(context.StockListPickingZone);
        if (context.StockListNonPickingZones != null)
            context.WorkingStockList.AddRange(context.StockListNonPickingZones);

        _logger.LogCheckpoint($"#MI3_STOCK_QUERY_OK - Picking: {context.StockListPickingZone?.Count ?? 0}, " +
                            $"NonPicking: {context.StockListNonPickingZones?.Count ?? 0}");
    }
}

/// <summary>
/// Paso 4: CГЎlculo de fechas mГӯnimas de vencimiento (FEFO/FIFO)
/// Target: ~70 lГӯneas
/// </summary>
public class DateCalculationStep : IPipelineStep
{
    private readonly IDateExpirationCalculator _dateCalculator;
    private readonly IReservationLogger _logger;

    public DateCalculationStep(IDateExpirationCalculator dateCalculator, IReservationLogger logger)
    {
        _dateCalculator = dateCalculator;
        _logger = logger;
    }

    public void Execute(ReservationContext context)
    {
        _logger.LogCheckpoint("#MI3_DATE_CALC_START");

        var defaultDate = new DateTime(1900, 1, 1);

        // Calcular fecha mГӯnima en zona Picking
        context.MinExpirationDatePickingZone = defaultDate;
        if (context.StockListPickingZone != null && context.StockListPickingZone.Count > 0)
        {
            context.MinExpirationDatePickingZone = _dateCalculator
                .GetMinimumExpirationDate(context.StockListPickingZone);
        }

        // Calcular fecha mГӯnima en zonas no-Picking
        context.MinExpirationDateNonPickingZones = defaultDate;
        if (context.StockListNonPickingZones != null && context.StockListNonPickingZones.Count > 0)
        {
            context.MinExpirationDateNonPickingZones = _dateCalculator
                .GetMinimumExpirationDate(context.StockListNonPickingZones);
        }

        // Determinar fecha mГӯnima global
        context.GlobalMinimumExpirationDate = _dateCalculator
            .GetMinimumExpirationDate(context.WorkingStockList);

        // Para Clavaud: calcular fechas para pallets completos/incompletos
        if (context.Configuration.Conservar_Zona_Picking_Clavaud)
        {
            var completePallets = context.StockListNonPickingZones?
                .Where(s => s.Pallet_Completo && !s.UbicacionPicking && s.UbicacionNivel > 0)
                .ToList();

            if (completePallets != null && completePallets.Count > 0)
            {
                context.MinExpirationCompletePalletsClavaud = completePallets.Min(s => s.Fecha_vence);
            }

            var incompletePallets = context.StockListNonPickingZones?
                .Where(s => !s.Pallet_Completo && !s.UbicacionPicking && s.UbicacionNivel > 0)
                .ToList();

            if (incompletePallets != null && incompletePallets.Count > 0)
            {
                context.MinExpirationIncompletePalletsClavaud = incompletePallets.Min(s => s.Fecha_vence);
            }
        }

        _logger.LogCheckpoint($"#MI3_DATE_CALC_OK - Min Global: {context.GlobalMinimumExpirationDate:yyyy-MM-dd}, " +
                            $"Picking: {context.MinExpirationDatePickingZone:yyyy-MM-dd}, " +
                            $"NonPicking: {context.MinExpirationDateNonPickingZones:yyyy-MM-dd}");
    }
}

/// <summary>
/// Paso 5: Loop de reserva usando Chain of Responsibility con fallbacks
/// Target: ~150 lГӯneas
/// </summary>
public class ReservationLoopStep : IPipelineStep
{
    private readonly IReservationHandler _handlerChain;
    private readonly IReservationLogger _logger;
    private const int MAX_ITERATIONS = 10; // ProtecciГіn contra loops infinitos

    public ReservationLoopStep(IReservationHandler handlerChain, IReservationLogger logger)
    {
        _handlerChain = handlerChain;
        _logger = logger;
    }

    public void Execute(ReservationContext context)
    {
        _logger.LogCheckpoint("#MI3_RESERVATION_LOOP_START");

        int iteration = 0;

        while (context.PendingQuantity > 0 && iteration < MAX_ITERATIONS)
        {
            iteration++;
            _logger.LogCheckpoint($"#MI3_ITERATION_{iteration} - Pendiente: {context.PendingQuantity}");

            double previousPending = context.PendingQuantity;

            // Determinar estrategia inicial (INICIAR_EN)
            DetermineStartingPoint(context);

            // Ejecutar cadena de handlers
            var result = _handlerChain.Handle(context);

            if (result.Success && result.ReservedQuantity > 0)
            {
                // Se reservГі algo
                context.PendingQuantity -= result.ReservedQuantity;
                context.PendingQuantity = Math.Round(context.PendingQuantity, 6);

                // Agregar reservas creadas
                if (result.Reservations != null && result.Reservations.Count > 0)
                {
                    context.CreatedReservations.AddRange(result.Reservations);
                }

                _logger.LogCheckpoint($"#MI3_RESERVED - Cantidad: {result.ReservedQuantity}, " +
                                    $"Pendiente restante: {context.PendingQuantity}, " +
                                    $"Caso: {result.CaseCode}");
            }

            // Si no hubo progreso, intentar explosiГіn o salir
            if (Math.Abs(context.PendingQuantity - previousPending) < 0.000001)
            {
                if (context.CanRetryWithExplosion())
                {
                    _logger.LogCheckpoint("#MI3_RETRY_WITH_EXPLOSION");
                    context.EnableExplosionMode();
                    continue;
                }
                else if (context.CanRetryWithUMBas())
                {
                    _logger.LogCheckpoint("#MI3_RETRY_WITH_UMBAS");
                    context.EnableUMBasMode();
                    continue;
                }
                else
                {
                    // No hay mГЎs opciones
                    break;
                }
            }
        }

        if (iteration >= MAX_ITERATIONS)
        {
            _logger.LogWarning($"#MI3_MAX_ITERATIONS - Se alcanzaron {MAX_ITERATIONS} iteraciones");
        }

        // Validar si se rechaza pedido incompleto
        if (context.PendingQuantity > 0.000001 && 
            context.Configuration.Rechazar_pedido_incompleto == tRechazarPedidoIncompleto.Si)
        {
            throw new Exception($"ERROR_PEDIDO_INCOMPLETO: Solicitado {context.Request.Cantidad}, " +
                              $"Reservado {context.Request.Cantidad - context.PendingQuantity}, " +
                              $"Faltante {context.PendingQuantity}");
        }

        _logger.LogCheckpoint($"#MI3_RESERVATION_LOOP_END - Iteraciones: {iteration}, " +
                            $"Reservado: {context.Request.Cantidad - context.PendingQuantity}");
    }

    private void DetermineStartingPoint(ReservationContext context)
    {
        // LГіgica similar al Select Case Iniciar_En del original
        context.StartingPoint = 0; // Default

        if (context.Configuration.Conservar_Zona_Picking_Clavaud)
        {
            var defaultDate = new DateTime(1900, 1, 1);

            if (context.MinExpirationCompletePalletsClavaud > context.GlobalMinimumExpirationDate &&
                context.MinExpirationCompletePalletsClavaud > defaultDate)
            {
                context.StartingPoint = 1; // INICIAR_EN_1: Pallets completos
            }
            else if (context.GlobalMinimumExpirationDate >= context.MinExpirationIncompletePalletsClavaud &&
                     context.MinExpirationIncompletePalletsClavaud > defaultDate)
            {
                context.StartingPoint = 2; // INICIAR_EN_2: Pallets incompletos
            }
        }

        if (context.StartingPoint == 0)
        {
            if (context.GlobalMinimumExpirationDate > context.MinExpirationDatePickingZone &&
                context.MinExpirationDatePickingZone > defaultDate)
            {
                context.StartingPoint = 3; // INICIAR_EN_3: Zona Picking
            }
        }

        _logger.LogCheckpoint($"#MI3_STARTING_POINT: {context.StartingPoint}");
    }
}

/// <summary>
/// Paso 6: Post-procesamiento (actualizar trasladoDet, logs finales)
/// Target: ~100 lГӯneas
/// </summary>
public class PostProcessingStep : IPipelineStep
{
    private readonly IReservationLogger _logger;

    public PostProcessingStep(IReservationLogger logger) => _logger = logger;

    public void Execute(ReservationContext context)
    {
        _logger.LogCheckpoint("#MI3_POST_PROCESSING_START");

        // Actualizar TrasladoDet si existe
        if (context.TrasladoDet != null && context.CreatedReservations.Count > 0)
        {
            foreach (var reservation in context.CreatedReservations)
            {
                if (reservation.IdPresentacion == 0)
                {
                    context.TrasladoDet.Quantity_Reserved_WMS += reservation.Cantidad;
                }
                else
                {
                    if (context.PedidoDet?.IdPresentacion == 0)
                    {
                        context.TrasladoDet.Quantity_Reserved_WMS += reservation.Cantidad;
                    }
                    else
                    {
                        var factor = context.DefaultPresentation?.Factor ?? 1;
                        context.TrasladoDet.Quantity_Reserved_WMS += 
                            Math.Round(reservation.Cantidad / factor, 6);
                    }
                }
            }

            clsLnI_nav_ped_traslado_det.Actualizar_Quantity_Reserved_WMS(
                context.TrasladoDet,
                context.Product,
                context.Connection,
                context.Transaction);

            _logger.LogCheckpoint($"#MI3_TRASLADO_UPDATED - Cantidad: {context.TrasladoDet.Quantity_Reserved_WMS}");
        }

        // Log de resumen
        var totalReserved = context.Request.Cantidad - context.PendingQuantity;
        _logger.LogCheckpoint($"#MI3_SUMMARY - Solicitado: {context.Request.Cantidad}, " +
                            $"Reservado: {totalReserved}, " +
                            $"Pendiente: {context.PendingQuantity}, " +
                            $"Reservas creadas: {context.CreatedReservations.Count}");

        _logger.LogCheckpoint("#MI3_POST_PROCESSING_END");
    }
}
