### 3. CHAIN OF RESPONSIBILITY

```csharp
/// <summary>
/// Interfaz para handlers de la cadena.
/// Cada handler puede procesar parcialmente y pasar al siguiente.
/// </summary>
public interface IReservationHandler
{
    IReservationHandler SetNext(IReservationHandler next);
    HandlerResult Handle(ReservationContext context);
}

public class HandlerResult
{
    public bool Success { get; set; }
    public double ReservedQuantity { get; set; }
    public List<clsBeStock_res> Reservations { get; set; }
    public string CaseCode { get; set; }
    public string Message { get; set; }
}

/// <summary>
/// Base para todos los handlers con lГіgica comГәn de cadena
/// </summary>
public abstract class BaseReservationHandler : IReservationHandler
{
    protected IReservationHandler _next;
    protected readonly IReservationLogger _logger;

    protected BaseReservationHandler(IReservationLogger logger)
    {
        _logger = logger;
    }

    public IReservationHandler SetNext(IReservationHandler next)
    {
        _next = next;
        return next;
    }

    public HandlerResult Handle(ReservationContext context)
    {
        if (CanHandle(context))
        {
            _logger.LogInfo($"Handler: {GetType().Name} - CanHandle = true");
            var result = ProcessReservation(context);

            // Si se reservГі algo pero aГәn queda pendiente, continuar cadena
            if (result.Success && context.PendingQuantity > 0.000001 && _next != null)
            {
                var nextResult = _next.Handle(context);

                // Combinar resultados
                if (nextResult.Success)
                {
                    result.ReservedQuantity += nextResult.ReservedQuantity;
                    result.Reservations.AddRange(nextResult.Reservations);
                    result.Message += " | " + nextResult.Message;
                }
            }

            return result;
        }
        else if (_next != null)
        {
            _logger.LogInfo($"Handler: {GetType().Name} - CanHandle = false, pasando al siguiente");
            return _next.Handle(context);
        }

        // Fin de cadena sin procesar
        return new HandlerResult { Success = false, Message = "No hay handler disponible" };
    }

    protected abstract bool CanHandle(ReservationContext context);
    protected abstract HandlerResult ProcessReservation(ReservationContext context);
}

// ========== HANDLERS CONCRETOS (Cada uno ~100-150 lГӯneas) ==========

/// <summary>
/// Handler 1: Reserva de pallets completos (Clavaud)
/// INICIAR_EN_1
/// </summary>
public class CompletePackagesHandler : BaseReservationHandler
{
    private readonly IStockReservationBuilder _builder;

    public CompletePackagesHandler(IStockReservationBuilder builder, IReservationLogger logger)
        : base(logger)
    {
        _builder = builder;
    }

    protected override bool CanHandle(ReservationContext context)
    {
        return context.StartingPoint == 1 &&
               context.Configuration.Conservar_Zona_Picking_Clavaud &&
               context.StockListNonPickingZones != null &&
               context.StockListNonPickingZones.Any(s => s.Pallet_Completo &&
                                                         !s.UbicacionPicking &&
                                                         s.Fecha_vence <= context.GlobalMinimumExpirationDate &&
                                                         s.UbicacionNivel > 0);
    }

    protected override HandlerResult ProcessReservation(ReservationContext context)
    {
        _logger.LogCheckpoint("#MI3_HANDLER_COMPLETE_PACKAGES_START");

        var result = new HandlerResult
        {
            Success = true,
            ReservedQuantity = 0,
            Reservations = new List<clsBeStock_res>(),
            CaseCode = "CASO_#1_COMPLETE_PACKAGES"
        };

        var completePallets = context.StockListNonPickingZones
            .Where(s => s.Pallet_Completo &&
                       !s.UbicacionPicking &&
                       s.Fecha_vence <= context.GlobalMinimumExpirationDate &&
                       s.UbicacionNivel > 0)
            .OrderBy(s => s.Fecha_vence)
            .ToList();

        foreach (var stock in completePallets)
        {
            if (context.PendingQuantity <= 0.000001) break;

            double quantityToReserve = Math.Min(context.PendingQuantity, stock.Cantidad);

            var reservation = _builder.BuildReservation(stock, context, quantityToReserve);
            reservation.IdStockRes = clsLnStock_res.MaxID(context.Connection, context.Transaction) + 1;

            clsLnStock_res.Insertar(reservation, context.Connection, context.Transaction);

            result.Reservations.Add(reservation);
            result.ReservedQuantity += quantityToReserve;

            // Actualizar listas
            stock.Cantidad -= quantityToReserve;
            clsLnStock_res.Restar_Stock_Reservado(
                new List<clsBeStock> { stock },
                context.Configuration,
                context.Connection,
                context.Transaction);

            _logger.LogReservation(reservation, result.CaseCode, 
                $"Pallet completo reservado: {quantityToReserve} de {stock.Lic_plate}");
        }

        _logger.LogCheckpoint($"#MI3_HANDLER_COMPLETE_PACKAGES_END - Reservado: {result.ReservedQuantity}");
        return result;
    }
}

