```csharp
/// <summary>
/// Contexto mutable que se comparte entre todos los pasos del pipeline
/// y handlers de la cadena. Contiene TODO el estado de la operaciГіn.
/// </summary>
public class ReservationContext
{
    // ===== INPUT =====
    public clsBeStock_res Request { get; set; }
    public int ProductId { get; set; }
    public clsBeConfigEnc Configuration { get; set; }
    public SqlConnection Connection { get; set; }
    public SqlTransaction Transaction { get; set; }
    public clsBePedidoDet PedidoDet { get; set; }
    public clsBeI_nav_ped_traslado_det TrasladoDet { get; set; }
    public int TareaReabasto { get; set; }
    public bool EsDevolucion { get; set; }
    public int LineNumber { get; set; }
    public string MachineName { get; set; }

    // ===== ENTITIES (cargadas en pipeline) =====
    public clsBeBodega Bodega { get; set; }
    public clsBeProducto Product { get; set; }
    public clsBeProducto_Presentacion DefaultPresentation { get; set; }

    // ===== STOCK LISTS (modificadas por handlers) =====
    public List<clsBeStock> StockListPickingZone { get; set; }
    public List<clsBeStock> StockListNonPickingZones { get; set; }
    public List<clsBeStock> WorkingStockList { get; set; } // Lista unificada

    // ===== DATES (calculadas en pipeline) =====
    public DateTime GlobalMinimumExpirationDate { get; set; }
    public DateTime MinExpirationDatePickingZone { get; set; }
    public DateTime MinExpirationDateNonPickingZones { get; set; }
    public DateTime MinExpirationCompletePalletsClavaud { get; set; }
    public DateTime MinExpirationIncompletePalletsClavaud { get; set; }

    // ===== STATE =====
    public double PendingQuantity { get; set; }
    public List<clsBeStock_res> CreatedReservations { get; set; }
    public List<int> ProcessStateFlags { get; set; } // Equivalente a ListaEstadosDeProceso
    public int StartingPoint { get; set; } // 0=default, 1=completos, 2=incompletos, 3=picking, 4=almacГ©n
    public bool IsExplosionModeEnabled { get; set; }
    public bool IsUMBasModeEnabled { get; set; }

    // ===== CACHES (evitar consultas repetidas) =====
    public List<clsBeBodega_ubicacion> CachedLocations { get; set; }
    public List<clsBeProducto_Presentacion> CachedPresentations { get; set; }

    // ===== ERROR HANDLING =====
    public bool HasError { get; set; }
    public string ErrorMessage { get; set; }

    // ===== HELPER METHODS =====
    public bool IsQuantityFullyReserved() => PendingQuantity <= 0.000001;

    public void SetError(string message)
    {
        HasError = true;
        ErrorMessage = message;
    }

    public bool CanRetryWithExplosion()
    {
        return !IsExplosionModeEnabled &&
               Configuration.Explosion_Automatica &&
               Request.IdPresentacion != 0;
    }

    public void EnableExplosionMode()
    {
        IsExplosionModeEnabled = true;
        // Re-query stock con explosiГіn habilitada
    }

    public bool CanRetryWithUMBas()
    {
        return !IsUMBasModeEnabled &&
               Request.IdPresentacion == 0 &&
               DefaultPresentation != null;
    }

    public void EnableUMBasMode()
    {
        IsUMBasModeEnabled = true;
        // Re-query stock en UMBas
    }
}
